describe('Purchase Order Creation Full Flow', () => {
  beforeEach(() => {
    // Login
    cy.login('debuguser3', 'password123');

    // Intercepts
    cy.intercept('POST', '/api/inboundPurchaseOrder/generate').as('generateOrder');
    cy.intercept('GET', '/api/warehouses*').as('getWarehouses');
    cy.intercept('GET', '/api/suppliers*').as('getSuppliers');
    cy.intercept('GET', '/api/products*').as('getProducts');

    // Visit page
    cy.visit('/supply-chain/purchase-order/create-inbound');
    cy.wait('@getWarehouses');
  });

  it('should display "--" for missing product fields in modal', () => {
    // Mock Product Response with missing fields
    const mockProducts = {
      content: [
        {
          id: 101,
          name: 'Complete Product',
          skuCode: 'CP001',
          status: 'ON_SHELF',
          categoryName: 'Electronics',
          brandZhName: 'Xiaomi',
          defaultSupplierName: 'Supplier A',
          skus: [{ id: 1001, skuCode: 'CP001-1', name: 'Standard', costPrice: 100 }]
        },
        {
          id: 102,
          name: 'Incomplete Product',
          skuCode: 'IP001',
          status: 'ON_SHELF',
          // Missing category, brand, supplier
          skus: [{ id: 1002, skuCode: 'IP001-1', name: 'Standard', costPrice: 200 }]
        }
      ],
      totalElements: 2,
      totalPages: 1
    };

    cy.intercept('GET', '/api/products*', {
      statusCode: 200,
      body: mockProducts
    }).as('getMockProducts');

    // Open Modal
    cy.contains('button', '选择商品').click({ force: true });
    cy.wait('@getMockProducts');

    // Wait for table
    cy.get('.ant-modal-body .ant-table-row', { timeout: 10000 }).should('have.length', 2);

    // Check first row (Complete)
    cy.get('.ant-modal-body .ant-table-row').eq(0).within(() => {
      cy.contains('Electronics').should('exist');
      cy.contains('Xiaomi').should('exist');
      cy.contains('Supplier A').should('exist');
    });

    // Check second row (Incomplete) - should show "--"
    cy.get('.ant-modal-body .ant-table-row').eq(1).within(() => {
      // Columns: [Checkbox, SKU Code, Name, Spec, Category, Brand, Supplier, Price]
      // Indices: 0, 1, 2, 3, 4, 5, 6, 7

      // Category (Index 4)
      cy.get('td').eq(4).should('contain', '--');
      // Brand (Index 5)
      cy.get('td').eq(5).should('contain', '--'); 
      // Supplier (Index 6)
      cy.get('td').eq(6).should('contain', '--');
    });

    // Close modal (Click first button usually Cancel)
    cy.get('.ant-modal-footer .ant-btn').first().click({ force: true });
  });

  it('should prevent submission when no product is selected', () => {
    // Select Supplier
    cy.get('input[id="supplierId"]').parent().click({ force: true });
    cy.wait(500);
    cy.get('.ant-select-dropdown:not(.ant-select-dropdown-hidden) .ant-select-item-option').first().click();

    // Select Warehouse
    cy.get('input[id="warehouseId"]').parent().click({ force: true });
    cy.wait(500);
    cy.get('.ant-select-dropdown:not(.ant-select-dropdown-hidden) .ant-select-item-option').first().click();

    // Fill Contact to avoid other errors
    cy.get('input[id="contactName"]').clear().type('Test Contact');
    cy.get('input[id="contactPhone"]').clear().type('13800000000');

    // Submit button should be disabled without products
    cy.contains('button', '提交入库采购单').should('be.disabled');

    // Check Red Warning Text
    cy.contains('* 请至少选择一件商品').should('be.visible');
  });

  it('should successfully create a purchase order with valid product', () => {
    // 1. Select Supplier
    cy.get('input[id="supplierId"]').parent().click({ force: true });
    cy.wait(500);
    cy.get('.ant-select-dropdown:not(.ant-select-dropdown-hidden) .ant-select-item-option').first().click();

    // 2. Select Warehouse
    cy.get('input[id="warehouseId"]').parent().click({ force: true });
    cy.wait(500);
    cy.get('.ant-select-dropdown:not(.ant-select-dropdown-hidden) .ant-select-item-option').first().click();

    // Fill Contact
    cy.get('input[id="contactName"]').clear().type('Test Contact');
    cy.get('input[id="contactPhone"]').clear().type('13800000000');

    // 3. Add Product (Real API)
    cy.contains('button', '选择商品').click({ force: true });
    cy.wait('@getProducts');

    // Wait for table and select first
    cy.wait(2000); 
    cy.get('input[type="checkbox"]').first().check({ force: true });
    cy.get('.ant-btn-primary').contains(/确\s*定|OK/).click({ force: true });
    cy.get('.ant-modal-content').should('not.exist');

    // Intercept submission to verify payload
    cy.intercept('POST', '/api/inboundPurchaseOrder/generate', (req) => {
      const items = req.body.items;
      expect(items).to.have.length.greaterThan(0);
      items.forEach((item: any) => {
        expect(item.productId).to.be.a('number').and.be.gt(0);
      });
      req.reply({ statusCode: 200, body: { id: 123, orderNo: 'PO123' } });
    }).as('submitOrder');

    // Submit form
    cy.get('button').contains('提交入库采购单').click();

    // Verify submission success
    cy.wait('@submitOrder');
    cy.get('.ant-message-success').should('contain', '入库采购单已创建');
  });
});

describe('Purchase Order Ship Functionality', () => {
  const poId = 123;
  const mockPO = {
    id: 123,
    orderNo: 'PO1234567890',
    status: 'CONFIRMED',
    items: [
      { skuId: 1, productId: 1, productName: 'Test Product', quantity: 10, unitPrice: 100, specName: 'Standard' }
    ],
    supplierId: 1,
    supplierName: 'Test Supplier',
    warehouseId: 1,
    warehouseName: 'Test Warehouse',
    totalAmount: 1000,
    createTime: '2023-10-27 10:00:00',
    receiver: 'Test Receiver',
    phone: '13800138000',
    address: 'Test Address'
  };

  beforeEach(() => {
    // Mock the purchase order data with proper wrapper
    const mockPO = {
        code: 200,
        message: 'Success',
        data: {
            id: 2,
            orderNo: 'PO1234567890',
            supplierName: 'Test Supplier',
            warehouseId: 1,
            warehouseName: 'Test Warehouse',
            status: 'CONFIRMED',
            createTime: '2023-10-27 10:00:00',
            purchaser: 'Test User',
            receiver: 'Test Receiver',
            phone: '13800138000',
            address: 'Test Address',
            expectTime: '2023-10-30',
            remarks: 'Test Remark',
            items: [
                {
                    id: 1,
                    skuId: 101,
                    productName: 'Test Product',
                    skuCode: 'SKU001',
                    spec: 'Spec A',
                    quantity: 100,
                    unitPrice: 10.00,
                    totalPrice: 1000.00
                }
            ],
            totalAmount: 1000.00
        }
    };

    // Intercept API calls
    cy.intercept('GET', '/api/purchase-orders/*', {
      statusCode: 200,
      body: mockPO
    }).as('getPO');

    cy.intercept('POST', '/api/purchase-orders/*/ship', {
      statusCode: 200,
      body: { code: 200, message: 'Success', data: true }
    }).as('shipPO');

    // Mock logistics tracks to prevent 404s
    cy.intercept('GET', '/api/logistics/tracks/*', {
        statusCode: 200,
        body: { code: 200, message: 'Success', data: [] }
    }).as('getTracks');

    // Visit the page with mocked auth
    cy.visit('/supply-chain/purchase-order/detail/2', {
        onBeforeLoad: (win) => {
            win.localStorage.setItem('token', 'mock-jwt-token');
            win.localStorage.setItem('user', JSON.stringify({ username: 'admin', role: 'ADMIN' }));
        }
    });

    // Wait for data to load
    cy.wait('@getPO');
  });

  it('should allow shipping an order', () => {
    // Wait for page load
    cy.wait('@getPO');

    // Verify page title to ensure app loaded
    cy.contains('采购单详情').should('be.visible');

    // Verify basic info is rendered
    cy.contains('PO1234567890').should('be.visible');

    // Verify item is rendered
    // Use a longer timeout or check for table row existence first
    cy.get('.ant-table-row').should('exist');
    cy.contains('Test Product').should('be.visible');

    // Wait for any loading spinners to disappear
    cy.get('.ant-spin-spinning').should('not.exist');

    // Ensure the row is stable by checking for text that shouldn't change
    cy.contains('Test Product').should('be.visible');

    // Wait for button to be available and UI to settle
    cy.wait(1000);
    cy.get('[data-testid="ship-button"]').should('be.visible').click();

    // Verify modal opens
    cy.get('.ant-modal-title').contains('订单发货').should('be.visible');

    // Click Ship button with retry/stability check
    cy.contains('订单发货').should('be.visible').click({ force: true });

    // Check modal and wait for animation
    cy.get('.ant-modal-content', { timeout: 10000 }).should('be.visible');
    cy.get('.ant-modal-title').contains('订单发货').should('be.visible');

    // Fill form
    // Default is Logistics
    // Use hidden input parent click for Select
    cy.get('input[id="shipCompany"]').parent().should('be.visible').click();
    // Wait for dropdown
    cy.get('.ant-select-dropdown').should('be.visible');
    cy.contains('.ant-select-item-option-content', '顺丰速运').should('be.visible').click();

    cy.get('input[id="shipNo"]').should('be.visible').type('SF1234567890');

    // Submit
    cy.contains('button', '确 定').should('be.visible').click();

    // Verify API call
    cy.wait('@shipPO').then((interception) => {
      expect(interception.request.body).to.have.property('shipCompany', 'SF'); // SF is the value for 顺丰速运
      expect(interception.request.body).to.have.property('shipNo', 'SF1234567890');
    });

    // Verify success message
    cy.contains('订单发货成功').should('be.visible');

    // Verify Inbound Order creation in localStorage
    cy.window().then((win) => {
      const inboundOrders = JSON.parse(win.localStorage.getItem('sc_inbound_orders_v2') || '[]');
      const createdOrder = inboundOrders.find((o: any) => o.poNo === mockPO.orderNo);
      expect(createdOrder).to.exist;
      expect(createdOrder.status).to.equal('pending');
      expect(createdOrder.items).to.have.length(1);
    });
  });
});

describe('Product ID Null Validation Fix', () => {
  beforeEach(() => {
    // 1. Login with valid credentials (using the debuguser created earlier)
    cy.login('debuguser3', 'password123');

    // 2. Intercept the Inbound Order Generation API to verify payload
    // We use a regex to match the endpoint
    cy.intercept('POST', '/api/inboundPurchaseOrder/generate').as('generateOrder');

    // 3. Intercept data loading APIs to ensure page is ready
    cy.intercept('GET', '/api/warehouses*').as('getWarehouses');
    cy.intercept('GET', '/api/suppliers*').as('getSuppliers');
    cy.intercept('GET', '/api/products*').as('getProducts');

    // 4. Visit the Inbound Order Creation Page
    cy.visit('/supply-chain/purchase-order/create-inbound');
  });

  it('should send a valid productId in the payload and receive 200 OK', () => {
    // Wait for initial data to load
    cy.wait('@getWarehouses');

    // --- Step 1: Select Supplier ---
    // Click the Supplier Select
    cy.get('input[id="supplierId"]').parent().click({ force: true });
    // Wait for dropdown animation
    cy.wait(500);
    // Select the first available supplier
    cy.get('.ant-select-dropdown:not(.ant-select-dropdown-hidden) .ant-select-item-option')
      .first()
      .click();

    // --- Step 2: Select Warehouse ---
    cy.get('input[id="warehouseId"]').parent().click({ force: true });
    cy.wait(500);
    // Select the first available warehouse (should be ID 27 or similar)
    cy.get('.ant-select-dropdown:not(.ant-select-dropdown-hidden) .ant-select-item-option')
      .first()
      .click();

    // --- Step 3: Add Product ---
    cy.log('Attempting to open Product Modal');
    cy.contains('button', '选择商品').should('be.visible').and('not.be.disabled').click({ force: true });

    // Wait for API call
    cy.wait('@getProducts').then((interception) => {
        cy.log('Products API Status:', interception.response?.statusCode);
        expect(interception.response?.statusCode).to.eq(200);
    });

    // Wait for table data to load (blindly wait for checkbox)
    cy.wait(2000); 
    cy.get('input[type="checkbox"]').first().check({ force: true });

    // Confirm selection (find the primary button in a modal-like container or just globally if unique)
    // The modal footer button usually has '确 定' or 'OK'
    cy.get('.ant-btn-primary').contains(/确\s*定|OK/).click({ force: true });

    // Verify modal is closed
    cy.wait(1000);
    cy.get('.ant-modal-content').should('not.exist');

    // Verify item is added to the table
    cy.get('.page-container .ant-table-tbody tr.ant-table-row').should('have.length.at.least', 1);

    // --- Step 4.1: Fill Required Fields (Contact) ---
    // Warehouse might not have manager, so fill manually to pass validation
    cy.get('input[id="contactName"]').clear().type('Test Contact');
    cy.get('input[id="contactPhone"]').clear().type('13800000000');

    // --- Step 4: Submit Order ---
    cy.contains('button', '提交入库采购单').click();

    // --- Step 5: Verify Request Payload & Response ---
    cy.wait('@generateOrder').then((interception) => {
      // 5.1 Verify Request Payload
      const requestBody = interception.request.body;
      cy.log('Request Payload:', JSON.stringify(requestBody));

      expect(requestBody).to.have.property('items');
      expect(requestBody.items).to. be.an('array').that.is.not.empty;

      const firstItem = requestBody.items[0];
      // CRITICAL ASSERTION: productId must not be null/undefined
      expect(firstItem).to.have.property('productId');
      expect(firstItem.productId).to.not.be.null;
      expect(firstItem.productId).to.be.a('number');

      // 5.2 Verify Response Status (Proves Backend Fix)
      // If the backend fix works, this should be 200 or 201.
      // If the backend fix fails, this would be 400 or 500.
      expect(interception.response?.statusCode).to.eq(200);
    });

    // Verify success message and redirection
    cy.contains('入库采购单已创建').should('be.visible');
    cy.url().should('include', '/supply-chain/purchase-order');
  });
});

