import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Select, Spin, message } from 'antd';
import { getBanks, getBankById, BankDTO } from '../../services/bankService';

interface BankSelectProps {
  value?: number;
  onChange?: (value: number, bank: BankDTO) => void;
  placeholder?: string;
  style?: React.CSSProperties;
  disabled?: boolean;
}

const BankSelect: React.FC<BankSelectProps> = ({
  value,
  onChange,
  placeholder = '请选择开户行',
  style,
  disabled = false,
}) => {
  const [options, setOptions] = useState<BankDTO[]>([]);
  const [fetching, setFetching] = useState(false);
  const fetchRef = useRef(0);

  const loadBanks = async (keyword: string = '') => {
    fetchRef.current += 1;
    const fetchId = fetchRef.current;
    setOptions([]);
    setFetching(true);

    try {
      const result = await getBanks({
        page: 0,
        size: 100, // Increase size to cover more banks
        keyword,
        status: true, // Only active banks
      });

      if (fetchId !== fetchRef.current) {
        // for fetch callback order
        return;
      }

      setOptions(result.content);
    } catch (error) {
      console.error('Failed to load banks', error);
      message.error('获取银行列表失败');
    } finally {
      if (fetchId === fetchRef.current) {
        setFetching(false);
      }
    }
  };

  // Debounce implementation
  const debounceFetcher = useMemo(() => {
    let timeoutId: any;
    return (value: string) => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
      timeoutId = setTimeout(() => {
        loadBanks(value);
      }, 500); // 500ms debounce
    };
  }, []);

  // Initial load
  useEffect(() => {
    loadBanks('');
  }, []);

  // Fetch initial value details if provided and not in options
  useEffect(() => {
    if (value && !options.find((o) => o.id === value)) {
      getBankById(value).then((bank) => {
         if (bank) {
             setOptions((prev) => {
                 if (prev.find(p => p.id === bank.id)) return prev;
                 return [bank, ...prev];
             });
         }
      }).catch(err => console.error("Failed to fetch selected bank", err));
    }
  }, [value]); // Depend on value. Note: options dependency might cause loop if not careful.

  // Handle selection
  const handleChange = (val: number) => {
    const selectedBank = options.find((b) => b.id === val);
    if (onChange && selectedBank) {
      onChange(val, selectedBank);
    }
  };

  return (
    <Select
      showSearch
      value={value}
      placeholder={placeholder}
      style={style}
      defaultActiveFirstOption={false}
      filterOption={false}
      loading={fetching}
      notFoundContent={fetching ? <Spin size="small" /> : null}
      options={options.map((d) => ({
        value: d.id,
        label: d.shortName || d.name, // Display name instead of code
      }))}
      onSearch={debounceFetcher}
      onChange={handleChange}
      onFocus={() => {
        if (options.length === 0) {
            loadBanks('');
        }
      }}
      disabled={disabled}
    />
  );
};

export default BankSelect;

import React from 'react';
import { Timeline, Card, Descriptions, Tag } from 'antd';
import { TruckOutlined, CheckCircleOutlined, ClockCircleOutlined } from '@ant-design/icons';
import { LogisticsTrack } from '../../types/logistics';

interface LogisticsTimelineProps {
  tracks: LogisticsTrack[];
}

const LogisticsTimeline: React.FC<LogisticsTimelineProps> = ({ tracks }) => {
  if (!tracks || tracks.length === 0) {
    return <div style={{ textAlign: 'center', color: '#999', padding: '20px' }}>暂无物流信息</div>;
  }

  const latest = tracks[0];

  return (
    <div className="logistics-timeline">
      <Card 
        title={
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span>物流详情 ({latest.logisticsProvider} - {latest.trackingNo})</span>
            <Tag color={latest.status === '已签收' ? 'green' : 'blue'}>{latest.status}</Tag>
          </div>
        }
        variant="borderless"
        className="mb-4"
      >
        <Timeline
          mode="left"
          items={tracks.map((track, index) => ({
            color: index === 0 ? 'green' : 'blue',
            dot: index === 0 ? <TruckOutlined style={{ fontSize: '16px' }} /> : <ClockCircleOutlined />,
            children: (
              <>
                <div style={{ fontWeight: 'bold', marginBottom: 4 }}>{track.status}</div>
                <div style={{ color: '#666', marginBottom: 4 }}>{track.description}</div>
                <div style={{ fontSize: '12px', color: '#999' }}>{track.eventTime}</div>
                {track.location && <div style={{ fontSize: '12px', color: '#999' }}>📍 {track.location}</div>}
              </>
            ),
          }))}
        />
      </Card>
    </div>
  );
};

export default LogisticsTimeline;

import React, { useState, useRef } from 'react';
import { FloatButton, Tabs, Table, Typography, Card, Alert, Modal } from 'antd';
import { FileTextOutlined, DatabaseOutlined, ApartmentOutlined } from '@ant-design/icons';
// @ts-ignore
import Draggable from 'react-draggable';

const { Title, Paragraph, Text } = Typography;

export interface FieldDefinition {
  name: string;
  type: string;
  length?: string;
  required?: boolean;
  unique?: boolean;
  defaultValue?: string;
  desc: string;
}

export interface PageDocProps {
  pageTitle: string;
  description: string;
  fields?: FieldDefinition[];
  flowchart?: string; // Mermaid code
  stateMachine?: string; // Mermaid code
  manual?: React.ReactNode;
}

const PageDoc: React.FC<PageDocProps> = ({
  pageTitle,
  description,
  fields,
  flowchart,
  stateMachine,
  manual
}) => {
  const [open, setOpen] = useState(false);
  const [disabled, setDisabled] = useState(true);
  const [bounds, setBounds] = useState({ left: 0, top: 0, bottom: 0, right: 0 });
  const draggleRef = useRef<HTMLDivElement>(null);

  const onStart = (_event: any, uiData: any) => {
    const { clientWidth, clientHeight } = window.document.documentElement;
    const targetRect = draggleRef.current?.getBoundingClientRect();
    if (!targetRect) {
      return;
    }
    setBounds({
      left: -targetRect.left + uiData.x,
      right: clientWidth - (targetRect.right - uiData.x),
      top: -targetRect.top + uiData.y,
      bottom: clientHeight - (targetRect.bottom - uiData.y),
    });
  };

  const fieldColumns = [
