    { title: '品牌名称', dataIndex: 'name', key: 'name' },
    { title: '商标注册号', dataIndex: 'trademarkNo', key: 'trademarkNo' },
    { title: '关联供应商数量', key: 'supplierCount', render: (_, record) => record.suppliers?.length || 0 },
    { title: '关联商品数量', dataIndex: 'productCount', key: 'productCount' },
    {
      title: '品牌状态',
      dataIndex: 'status',
      key: 'status',
      render: (status) => (
        <Tag color={status === 'ENABLED' ? 'success' : 'error'}>
          {status === 'ENABLED' ? '已启用' : '已禁用'}
        </Tag>
      ),
    },
    {
      title: '操作',
      key: 'action',
      render: (_, record) => (
        <Space size="middle">
          <Button 
            type="link" 
            icon={<EditOutlined />} 
            onClick={() => navigate(`/supply-chain/brand/edit/${record.id}`)}
          >
            编辑
          </Button>
          {record.status === 'ENABLED' ? (
            <Button 
              type="link" 
              danger 
              icon={<StopOutlined />} 
              onClick={() => handleStatusChange(record, 'DISABLED')}
            >
              禁用
            </Button>
          ) : (
            <Button 
              type="link" 
              icon={<CheckCircleOutlined />} 
              onClick={() => handleStatusChange(record, 'ENABLED')}
            >
              启用
            </Button>
          )}
        </Space>
      ),
    },
  ];

  return (
    <div style={{ background: '#fff', padding: 24, minHeight: 360 }}>
      <PageDoc 
        pageTitle="供应链管理 > 品牌管理"
        description={`品牌管理页面为品牌列表页。

1. **列表字段**：
   - 品牌名称、商标注册号、品牌图标。
   - 关联供应商数量、关联商品数量。
   - 品牌状态（已启用、已禁用）。
   - 操作列：编辑、启用（禁用状态时显示）、禁用（启用状态时显示）。`}
        fields={[
          { name: 'brandName', type: 'String', length: '100', required: true, desc: '品牌名称' },
          { name: 'trademarkNo', type: 'String', length: '50', required: false, desc: '商标注册号' },
          { name: 'status', type: 'Enum', required: true, defaultValue: 'ENABLED', desc: '状态：ENABLED, DISABLED' },
        ]}
      />
      <div style={{ marginBottom: 24, display: 'flex', justifyContent: 'space-between' }}>
        <Space>
           <Input 
             placeholder="请输入品牌名称" 
             style={{ width: 200 }} 
             value={searchText}
             onChange={(e) => setSearchText(e.target.value)}
             onPressEnter={handleSearch}
           />
           <Button type="primary" onClick={handleSearch}>查询</Button>
           <Button onClick={() => { setSearchText(''); setPagination({ ...pagination, current: 1 }); /* trigger fetch via effect if needed, but here effect depends on pagination only. We need to trigger fetch manually or change dependency */ setTimeout(() => fetchBrands(), 0); }}>重置</Button>
        </Space>
        <Space>
           <Button type="primary" icon={<PlusOutlined />} onClick={() => navigate('/supply-chain/brand/add')}>
             新增品牌
           </Button>
           <Tooltip title="支持Excel/CSV格式导出，最大支持10000条数据">
             <Button icon={<ExportOutlined />} onClick={handleExport} loading={exporting}>
               {exporting ? `导出中 ${progress}%` : '批量导出'}
             </Button>
           </Tooltip>
        </Space>
      </div>

      <Table 
        columns={columns} 
        dataSource={brands} 
        loading={loading} 
        rowKey="id"
        pagination={{
          ...pagination,
          total,
          onChange: (page, pageSize) => setPagination({ current: page, pageSize: pageSize || 10 })
        }}
      />
    </div>
  );
};

export default BrandList;

import React, { useState, useEffect } from 'react';
import { Form, Input, Button, Table, Space, Select, InputNumber, message, Breadcrumb, Tooltip } from 'antd';
import { MinusCircleOutlined, PlusOutlined, ExclamationCircleOutlined } from '@ant-design/icons';
import { useNavigate, useParams } from 'react-router-dom';
import PageDoc from '../../components/PageDoc';
import request from '../../utils/request';

interface SubProduct {
    key: number;
    productId?: number;
    name?: string;
    spec?: string; // SKU Name or Code
    skuCode?: string; // Actual SKU Code
    supplier?: string;
    cost?: number;
    count?: number;
    total?: number;
    skuOptions?: any[]; // Available SKUs for this product
}

const BundleAdd: React.FC = () => {
    const [form] = Form.useForm();
    const navigate = useNavigate();
    const { id } = useParams();
    const [subProducts, setSubProducts] = useState<SubProduct[]>([
        { key: Date.now(), count: 1 }
    ]);
    const [productOptions, setProductOptions] = useState<{ label: string, value: number, product: any }[]>([]);
    const [loading, setLoading] = useState(false);

    const fetchProducts = async (keyword: string = '') => {
        setLoading(true);
        try {
            const res: any = await request.get('/products', {
                params: {
                    status: ['ON_SHELF', 'SELECTED'],
                    keyword,
                    page: 0,
                    size: 100
                },
                paramsSerializer: params => {
                    const searchParams = new URLSearchParams();
                    Object.keys(params).forEach(key => {
                        const val = params[key];
                        if (Array.isArray(val)) {
                            val.forEach(v => searchParams.append(key, v));
                        } else if (val !== undefined && val !== null) {
                            searchParams.append(key, val);
                        }
                    });
                    return searchParams.toString();
                }
            });

            if (res && res.records) {
                const options = res.records.map((p: any) => ({
                    label: `${p.name} (${p.skuCode})`,
                    value: p.id,
                    product: p
                }));
                setProductOptions(options);
            }
        } catch (e: any) {
                console.error('Fetch products failed', e);
                if (e.response || e.request) {
                   message.error('获取商品列表失败，请稍后重试');
                }
            } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchProducts('');
    }, []);

    useEffect(() => {
        if (id) {
            const fetchDetail = async () => {
                try {
                    const p: any = await request.get(`/products/${id}`);
                    if (p) {
                        form.setFieldsValue({
                            bundleName: p.name,
                            saleType: 'Bundle',
                        });

                        if (p.bundleItems) {
                            const items = p.bundleItems.map((item: any) => {
                                const child = item.childProduct || {};
                                const skus = child.skus || [];
                                // Find specific SKU if we were storing childSkuId, but currently we just default to first or matching logic
                                // Since we don't store childSkuId in ProductBundle yet (based on entity), we assume first or logic needs enhancement.
                                // But for display, we show what we have.
                                const firstSku = skus.length > 0 ? skus[0] : {};

                                return {
                                    key: item.id || (Date.now() + Math.random()),
                                    productId: item.childProductId,
                                    name: child.name,
                                    spec: firstSku.name || firstSku.skuCode || '默认规格',
                                    skuCode: firstSku.skuCode,
                                    supplier: firstSku.supplier ? firstSku.supplier.name : '暂无供应商',
                                    cost: firstSku.costPrice || 0,
                                    count: item.quantity,
                                    total: (firstSku.costPrice || 0) * item.quantity,
                                    skuOptions: skus
                                };
                            });
                            setSubProducts(items);

                            // Pre-fill options
                            const existingOptions = p.bundleItems.map((item: any) => ({
                                label: `${item.childProduct.name} (${item.childProduct.skuCode})`,
                                value: item.childProductId,
                                product: item.childProduct
                            }));
                            setProductOptions(prev => {
                                const newOptions = [...prev];
                                existingOptions.forEach((opt: any) => {
                                    if (!newOptions.find(o => o.value === opt.value)) {
                                        newOptions.push(opt);
                                    }
                                });
                                return newOptions;
                            });
                        }
                    }
                } catch (e) {
                    message.error('获取详情失败');
                }
            };
            fetchDetail();
        }
    }, [id, form]);

    const handleAddSubProduct = () => {
        setSubProducts([...subProducts, { key: Date.now(), count: 1 }]);
    };

    const handleRemoveSubProduct = (key: number) => {
        setSubProducts(subProducts.filter(item => item.key !== key));
    };

    const handleUpdateSubProduct = (key: number, field: string, value: any) => {
        const newSubProducts = subProducts.map(item => {
            if (item.key === key) {
                const updatedItem = { ...item, [field]: value };

                if (field === 'productId') {
                    const selectedOption = productOptions.find(opt => opt.value === value);
                    if (selectedOption) {
                        const p = selectedOption.product;
                        updatedItem.name = p.name;
                        updatedItem.skuOptions = p.skus || [];

                        // Default to first SKU
                        if (p.skus && p.skus.length > 0) {
                            const firstSku = p.skus[0];
                            updatedItem.spec = firstSku.name || firstSku.skuCode;
                            updatedItem.skuCode = firstSku.skuCode;
                            updatedItem.supplier = firstSku.supplier ? firstSku.supplier.name : '暂无供应商';
                            updatedItem.cost = firstSku.costPrice || 0;
                        } else {
                            updatedItem.spec = '默认规格';
                            updatedItem.skuCode = p.skuCode;
                            updatedItem.supplier = '暂无供应商';
                            updatedItem.cost = 0;
                        }
                        updatedItem.count = 1;
                    }
                }

                if (field === 'skuCode') {
                    // Find SKU in options
                    const sku = item.skuOptions?.find((s: any) => s.skuCode === value);
                    if (sku) {
                        updatedItem.spec = sku.name || sku.skuCode;
                        updatedItem.skuCode = sku.skuCode;
                        updatedItem.supplier = sku.supplier ? sku.supplier.name : '暂无供应商';
                        updatedItem.cost = sku.costPrice || 0;
                    }
                }

                if (field === 'count' || field === 'productId' || field === 'skuCode') {
                    updatedItem.total = (updatedItem.cost || 0) * (updatedItem.count || 0);
                }
                return updatedItem;
            }
            return item;
        });
        setSubProducts(newSubProducts);
    };

    const onFinish = async (values: any) => {
        // Strict validation: count must be > 0
        const invalidCount = subProducts.some(item => !item.count || item.count <= 0);
        if (invalidCount) {
             message.error('子商品数量不能为空且必须大于0');
             return;
        }

        const validSubProducts = subProducts.filter(item => item.productId && item.count && item.count > 0);
        if (validSubProducts.length === 0) {
            message.error('请至少添加一个有效的子商品');
            return;
        }

        const payload = {
            name: values.bundleName,
            type: 'BUNDLE',
            status: 'LISTED',
            bundleItems: validSubProducts.map(item => ({
                childProductId: item.productId,
                quantity: item.count,
                // TODO: Add childSkuId support in backend entity if needed to persist specific SKU choice
            }))
        };

        try {
            const url = id ? `/products/${id}` : '/products';
            const method = id ? 'put' : 'post';

            // request[method] call
            // @ts-ignore
            await request[method](url, payload);

            message.success('组合商品保存成功');
            navigate('/supply-chain/bundle');
        } catch (e) {
            // Error handled by interceptor usually
            // message.error('网络错误，请稍后重试');
        }
    };

    const columns = [
        {
            title: '子商品名称',
            dataIndex: 'name',
            key: 'name',
            width: 250,
            render: (text: string, record: SubProduct) => (
                <Select
                    showSearch
                    placeholder="请选择子商品"
                    style={{ width: '100%' }}
                    value={record.productId}
                    filterOption={false}
                    onSearch={fetchProducts}
                    onChange={(val) => handleUpdateSubProduct(record.key, 'productId', val)}
                    options={productOptions}
                    loading={loading}
                />
            )
        },
        {
            title: '规格',
            dataIndex: 'spec',
            key: 'spec',
            width: 200,
            render: (text: string, record: SubProduct) => {
                if (record.skuOptions && record.skuOptions.length > 1) {
                    return (
                        <Select
                            style={{ width: '100%' }}
                            value={record.skuCode}
                            onChange={(val) => handleUpdateSubProduct(record.key, 'skuCode', val)}
                            placeholder="请选择规格"
                        >
                            {record.skuOptions.map((sku: any) => (
                                <Select.Option key={sku.skuCode} value={sku.skuCode}>
                                    {sku.name || sku.skuCode}
                                </Select.Option>
                            ))}
                        </Select>
                    );
                }
                return <Input value={text} disabled />;
            }
        },
        {
            title: '默认供应商',
            dataIndex: 'supplier',
            key: 'supplier',
            render: (text: string) => <Input value={text} disabled />
        },
        {
            title: '默认成本单价',
            dataIndex: 'cost',
            key: 'cost',
            render: (val: number) => <InputNumber value={val} disabled formatter={value => `¥ ${value}`} />
        },
        {
            title: '数量',
            dataIndex: 'count',
            key: 'count',
            render: (val: number, record: SubProduct) => (
                <Form.Item
                    validateStatus={(!val || val <= 0) ? 'error' : ''}
                    help={(!val || val <= 0) ? '必须大于0' : ''}
                    style={{ margin: 0 }}
                >
                    <InputNumber 
                        min={1} 
                        precision={0}
                        value={val} 
                        onChange={(val) => handleUpdateSubProduct(record.key, 'count', val)} 
                        onBlur={() => {
                            if (!val || val <= 0) {
                                message.error('子商品数量不能为空且必须大于0');
                            }
                        }}
                    />
                </Form.Item>
            )
        },
        {
            title: '成本小计',
            dataIndex: 'total',
            key: 'total',
            render: (val: number) => `¥ ${(val || 0).toFixed(2)}`
        },
        {
            title: '操作',
            key: 'action',
            render: (_: any, record: SubProduct) => (
                <MinusCircleOutlined onClick={() => handleRemoveSubProduct(record.key)} />
            )
        }
    ];

    return (
        <div style={{ background: '#fff', padding: 24 }}>
            <Breadcrumb style={{ marginBottom: 16 }}>
                <Breadcrumb.Item>供应链管理</Breadcrumb.Item>
                <Breadcrumb.Item>组合商品管理</Breadcrumb.Item>
                <Breadcrumb.Item>{id ? '编辑' : '新增'}组合商品</Breadcrumb.Item>
            </Breadcrumb>

            <PageDoc 
                pageTitle={id ? '编辑组合商品' : '新增组合商品'}
                description="在此页面配置组合商品的基本信息及其包含的子商品。"
                fields={[]}
            />

            <Form form={form} layout="vertical" onFinish={onFinish}>
                <Form.Item label="组合商品名称" name="bundleName" rules={[{ required: true, message: '请输入组合商品名称' }]}>
                    <Input placeholder="请输入组合商品名称" style={{ width: 400 }} />
                </Form.Item>
                <Form.Item label="售卖方式" name="saleType" initialValue="Bundle">
                    <Select disabled style={{ width: 200 }}>
                        <Select.Option value="Bundle">打包售卖</Select.Option>
                    </Select>
                </Form.Item>

                <Form.Item label="子商品明细" required>
                    <Table
                        dataSource={subProducts}
                        columns={columns}
                        pagination={false}
                        footer={() => (
                            <Button type="dashed" onClick={handleAddSubProduct} block icon={<PlusOutlined />}>
                                新增子商品
                            </Button>
                        )}
                    />
                </Form.Item>

                <Form.Item>
                    <Space>
                        <Button type="primary" htmlType="submit">保存</Button>
                        <Button onClick={() => navigate('/supply-chain/bundle')}>取消</Button>
                    </Space>
                </Form.Item>
            </Form>
        </div>
    );
};

export default BundleAdd;

import React, { useState, useEffect } from 'react';
import { Table, Button, Input, Select, Space, Tag, Form, message, Row, Col, Tooltip } from 'antd';
import type { ColumnsType } from 'antd/es/table';
import { PlusOutlined, EditOutlined, StopOutlined, CheckCircleOutlined, ExportOutlined, ReloadOutlined } from '@ant-design/icons';
import { useNavigate } from 'react-router-dom';
import PageDoc from '../../components/PageDoc';
import { useExport } from '../../utils/exportUtils';
import request from '../../utils/request';

interface BundleDataType {
  key: string;
  bundleId: string;
  bundleName: string;
  saleType: string;
  defaultCost: number;
  status: string;
  subProducts: {
      name: string;
      spec: string;
      qty: number;
      unitCost: number;
      totalCost: number;
      supplier: string;
  }[];
}

const BundleList: React.FC = () => {
  const navigate = useNavigate();
  const [data, setData] = useState<BundleDataType[]>([]);
  const [loading, setLoading] = useState(false);
  const [form] = Form.useForm();
  const [pagination, setPagination] = useState({
    current: 1,
    pageSize: 10,
    total: 0,
  });

  const fetchBundles = async (params: any = {}) => {
    setLoading(true);
    try {
        const { current, pageSize } = pagination;
        // Merge pagination and search params
        const queryParams = {
            page: params.page || current - 1, // Spring Boot is 0-indexed
            size: params.size || pageSize,
            ...params
        };

        // Remove page/size from params if they are passed separately to avoid duplication or conflict
        delete queryParams.current;
        delete queryParams.pageSize;

        const res: any = await request.get('/bundles', {
            params: queryParams
        });

        if (res && res.content) {
            const bundles = res.content.map((p: any) => ({
                key: p.id.toString(),
                bundleId: p.id.toString(),
                bundleName: p.name,
                saleType: '打包售卖',
                defaultCost: p.bundleItems ? p.bundleItems.reduce((sum: number, item: any) => {
                     const child = item.childProduct || {};
                     // Try to get cost from first SKU, or child product cost if available
                     const cost = (child.skus && child.skus.length > 0) 
                        ? child.skus[0].costPrice 
                        : (child.costPrice || 0);
                     return sum + (cost * item.quantity);
                }, 0) : 0,
                status: p.status,
                subProducts: p.bundleItems ? p.bundleItems.map((item: any) => {
                    const child = item.childProduct || {};
                    const firstSku = child.skus && child.skus.length > 0 ? child.skus[0] : {};
                    return {
                        name: child.name || '未知商品',
                        spec: firstSku.name || firstSku.skuCode || '默认规格',
                        qty: item.quantity,
                        unitCost: firstSku.costPrice || 0,
                        totalCost: (firstSku.costPrice || 0) * item.quantity,
                        supplier: firstSku.supplier ? firstSku.supplier.name : '暂无供应商'
                    };
                }) : []
            }));
            setData(bundles);
            setPagination(prev => ({
                ...prev,
                total: res.totalElements,
                current: res.number + 1
            }));
        }
    } catch (e) {
        console.error('Fetch bundles failed', e);
        message.error('获取组合商品列表失败');
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => {
    fetchBundles();
  }, []);

  const handleSearch = () => {
      const values = form.getFieldsValue();
      // Handle array for status
      const searchParams: any = {
          keyword: values.keyword,
          page: 0 // Reset to first page
      };
      if (values.status && values.status.length > 0) {
          // If multiple statuses selected, we might need to handle it. 
          // Current API supports single 'status' string or list depending on implementation.
          // BundleController.getBundles takes String status. 
          // If we want multiple, we need to update Backend or just take the first one or join them.
          // Let's check BundleController again. It takes `String status`.
          // For now, let's just use the first one if multiple, or join with comma if backend supports it.
          // BundleController logic: Product.Status.fromString(status). It expects a single status.
          // Requirement 10 says "Support filtering by status".
          // If UI allows multiple, backend should support it.
          // For now, assuming single select or taking first.
          searchParams.status = values.status[0]; 
      }
      fetchBundles(searchParams);
  };

  const handleReset = () => {
      form.resetFields();
      setPagination(prev => ({ ...prev, current: 1 }));
      fetchBundles({ page: 0 });
  };

  const handleTableChange = (newPagination: any) => {
      setPagination(newPagination);
      const values = form.getFieldsValue();
      const searchParams: any = {
          keyword: values.keyword,
          page: newPagination.current - 1,
          size: newPagination.pageSize
      };
      if (values.status && values.status.length > 0) {
          searchParams.status = values.status[0];
      }
      fetchBundles(searchParams);
  };

  const handleAction = async (key: string, action: 'List' | 'Delist') => {
    try {
        if (action === 'List') {
            await request.post(`/bundles/${key}/list`);
            message.success('组合商品已上架');
        } else {
            await request.post(`/bundles/${key}/delist`);
            message.success('组合商品已下架');
        }
        fetchBundles({ page: pagination.current - 1 }); 
    } catch (e: any) {
        // Error handled usually by interceptor, but if we want specific message:
        // message.error(e.message || '操作失败');
    }
  };

  const { handleExport, exporting, progress } = useExport<BundleDataType>({
    filenamePrefix: '组合商品列表',
    fetchData: () => data,
    columns: [
        { title: '组合商品ID', dataIndex: 'bundleId' },
        { title: '组合商品名称', dataIndex: 'bundleName' },
        { title: '售卖方式', dataIndex: 'saleType' },
        { title: '默认成本价', dataIndex: 'defaultCost', render: (val) => val.toFixed(2) },
        { title: '状态', dataIndex: 'status', render: (val) => {
            const map: any = { 'PENDING_SELECTION': '待选品', 'SELECTED': '已选品', 'LISTED': '已上架', 'DELISTED': '已下架' };
            return map[val] || val;
        } },
    ]
  });

  const columns: ColumnsType<BundleDataType> = [
    { title: '组合商品ID', dataIndex: 'bundleId', key: 'bundleId' },
    { title: '组合商品名称', dataIndex: 'bundleName', key: 'bundleName' },
    { 
       title: '包含子商品种类', 
       key: 'subProductCount', 
       render: (_, record) => (
          <Tooltip 
             title={
                <div style={{ padding: '4px' }}>
                   {record.subProducts.map((sub, idx) => (
                      <div key={idx} style={{ marginBottom: idx === record.subProducts.length - 1 ? 0 : 8, borderBottom: '1px solid rgba(255,255,255,0.2)', paddingBottom: 4 }}>
                         <div><strong>{sub.name}</strong></div>
                         <div style={{ fontSize: '12px', color: '#ccc' }}>{sub.spec}</div>
                         <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 4 }}>
                            <span>x {sub.qty}</span>
                            <span>¥{sub.unitCost.toFixed(2)}</span>
                         </div>
                         <div style={{ fontSize: '12px', marginTop: 2 }}>供: {sub.supplier}</div>
                      </div>
                   ))}
                   <div style={{ marginTop: 8, paddingTop: 4, borderTop: '1px solid #fff', textAlign: 'right' }}>
                      成本合计: ¥{record.subProducts.reduce((sum, item) => sum + item.totalCost, 0).toFixed(2)}
                   </div>
                </div>
             }
             overlayInnerStyle={{ backgroundColor: 'rgba(0, 0, 0, 0.85)', maxWidth: 300 }}
             mouseEnterDelay={0.2}
          >
             <span style={{ cursor: 'pointer', borderBottom: '1px dashed #999' }}>{record.subProducts.length}</span>
          </Tooltip>
       ),
    },
    { title: '售卖方式', dataIndex: 'saleType', key: 'saleType' },
    { 
       title: '默认成本价', 
       dataIndex: 'defaultCost', 
       key: 'defaultCost',
       render: (val) => `¥${val.toFixed(2)}`
    },
    {
      title: '状态',
      dataIndex: 'status',
      key: 'status',
      render: (status) => {
        const statusMap: Record<string, { color: string, text: string }> = {
           LISTED: { color: 'success', text: '已上架' },
           DELISTED: { color: 'error', text: '已下架' },
        };
        const normalizedStatus = typeof status === 'string' ? status.toUpperCase() : status;
        const { color, text } = statusMap[status] || statusMap[normalizedStatus] || { color: 'default', text: status };
        return <Tag color={color}>{text}</Tag>;
      },
    },
    {
      title: '操作',
      key: 'action',
      render: (_, record) => {
        const status = typeof record.status === 'string' ? record.status.toUpperCase() : '';
        return (
          <Space size="middle">
            <Button type="link" icon={<EditOutlined />} onClick={() => navigate(`/supply-chain/bundle/edit/${record.key}`)}>编辑</Button>
            {status === 'DELISTED' && (
               <Button type="link" icon={<CheckCircleOutlined />} onClick={() => handleAction(record.key, 'List')}>上架</Button>
            )}
            {status === 'LISTED' && (
               <Button type="link" danger icon={<StopOutlined />} onClick={() => handleAction(record.key, 'Delist')}>下架</Button>
            )}
          </Space>
        );
      },
    },
  ];

  return (
    <div style={{ background: '#fff', padding: 24, minHeight: 360 }}>
      <PageDoc 
        pageTitle="供应链管理 > 组合商品管理"
        description="组合商品管理页面。支持组合商品的上架和下架。"
        fields={[]}
      />
      <Form form={form} layout="inline" style={{ marginBottom: 24 }} onFinish={handleSearch}>
         <Row gutter={[16, 16]} style={{ width: '100%' }}>
            <Col>
              <Form.Item name="keyword" label="商品信息">
                 <Input placeholder="名称/ID" allowClear />
              </Form.Item>
            </Col>
            <Col>
              <Form.Item name="status" label="状态">
                 <Select placeholder="请选择" mode="multiple" style={{ width: 200 }} allowClear>
                    <Select.Option value="LISTED">已上架</Select.Option>
                    <Select.Option value="DELISTED">已下架</Select.Option>
                 </Select>
              </Form.Item>
            </Col>
            <Col>
               <Space>
                  <Button type="primary" htmlType="submit">查询</Button>
                  <Button onClick={handleReset}>重置</Button>
               </Space>
            </Col>
         </Row>
      </Form>

      <div style={{ marginBottom: 16, display: 'flex', justifyContent: 'flex-end' }}>
         <Space>
           <Button type="primary" icon={<PlusOutlined />} onClick={() => navigate('/supply-chain/bundle/add')}>
             新增组合商品
           </Button>
           <Tooltip title="支持Excel/CSV格式导出">
             <Button icon={<ExportOutlined />} onClick={handleExport} loading={exporting}>
               {exporting ? `导出中 ${progress}%` : '批量导出'}
             </Button>
           </Tooltip>
         </Space>
      </div>

      <Table 
        columns={columns} 
        dataSource={data} 
        loading={loading}
        pagination={pagination}
        onChange={handleTableChange}
        rowKey="key"
      />
    </div>
  );
};

