      const selectedBatchDetails = inventory.filter(b => selectedBatches.includes(b.batchNo));

      for (const batch of selectedBatchDetails) {
          if (remainingQty <= 0) break;
          const takeQty = Math.min(batch.currentQty, remainingQty);
