            <div style={{ marginTop: 16, display: 'flex', justifyContent: 'space-between' }}>
                <Space>
                    <Button type="primary" onClick={handleBatchConfirm} disabled={selectedRowKeys.length === 0}>批量确认</Button>
                    <Upload 
                        accept=".xls,.xlsx" 
                        showUploadList={false} 
                        beforeUpload={handleFileUpload}
                    >
                        <Button icon={<ImportOutlined />}>导入文件批量确认</Button>
                    </Upload>
                    <Button danger onClick={handleBatchReject} disabled={selectedRowKeys.length === 0}>批量拒回</Button>
                </Space>
            </div>
        </Card>

        {/* Sub-warehouse Ship Modal */}
        <Modal
            title="分仓直接发货"
            open={shipModalOpen}
            onCancel={() => setShipModalOpen(false)}
            onOk={submitSubWarehouseShip}
        >
            <p>将订单转换为出库单，由自有仓库直接发货。</p>
            <Form layout="vertical">
                <Form.Item label="发货仓库">
                    <Select 
                        options={warehouses.map(w => ({ label: w.name, value: w.code }))}
                        onChange={setSelectedWarehouse}
                        value={selectedWarehouse}
                    />
                </Form.Item>
                {/* Inventory Selection (Simplified) */}
                {selectedWarehouse && (
                     <Form.Item label="库存批次">
                         <Select 
                            mode="multiple"
                            options={getAvailableBatches()
                                .map(i => ({ label: `${i.batchNo} (余${i.currentQty})`, value: i.batchNo }))
                            }
                            onChange={setSelectedBatches}
                            value={selectedBatches}
                         />
                     </Form.Item>
                )}
            </Form>
        </Modal>

        {/* Import Modal */}
        <Modal
            title={importSummary.total > 0 ? "批量导入确认" : "批量导入修改"}
            open={isImportModalOpen}
            onCancel={() => {
                setIsImportModalOpen(false);
                setImportSummary({ total: 0, success: 0, error: 0, changes: [], errors: [] });
            }}
            width={importSummary.total > 0 ? 800 : 520}
            footer={importSummary.total > 0 ? [
                <Button key="cancel" onClick={() => setIsImportModalOpen(false)}>取消</Button>,
                <Button key="submit" type="primary" onClick={confirmBatchImport}>确认变更</Button>
            ] : null}
        >
             {importSummary.total === 0 ? (
                 <div style={{ textAlign: 'center', padding: 20 }}>
                     <Upload.Dragger beforeUpload={handleFileUpload} showUploadList={false}>
                         <p className="ant-upload-drag-icon"><UploadOutlined /></p>
                         <p className="ant-upload-text">点击或拖拽文件到此区域上传</p>
                         <p className="ant-upload-hint">支持 .xlsx, .xls 格式</p>
                     </Upload.Dragger>
                 </div>
             ) : (
                 <div style={{ marginBottom: 16 }}>
                    <Row gutter={16} style={{ marginBottom: 24 }}>
                        <Col span={8}>
                            <div style={{ textAlign: 'center', background: '#f0f2f5', padding: 16, borderRadius: 4 }}>
                                <div style={{ fontSize: 24, fontWeight: 'bold' }}>{importSummary.total}</div>
                                <div style={{ color: '#666' }}>总记录数</div>
                            </div>
                        </Col>
                        <Col span={8}>
                            <div style={{ textAlign: 'center', background: '#f6ffed', padding: 16, borderRadius: 4, border: '1px solid #b7eb8f' }}>
                                <div style={{ fontSize: 24, fontWeight: 'bold', color: '#52c41a' }}>{importSummary.success}</div>
                                <div style={{ color: '#52c41a' }}>匹配成功</div>
                            </div>
                        </Col>
                        <Col span={8}>
                            <div style={{ textAlign: 'center', background: '#fff1f0', padding: 16, borderRadius: 4, border: '1px solid #ffa39e' }}>
                                <div style={{ fontSize: 24, fontWeight: 'bold', color: '#f5222d' }}>{importSummary.error}</div>
                                <div style={{ color: '#f5222d' }}>匹配失败</div>
                            </div>
                        </Col>
                    </Row>

                    {importSummary.changes.length > 0 && (
                        <>
                            <Divider>变更预览 ({importSummary.changes.length})</Divider>
                            <Table
                                dataSource={importSummary.changes}
                                size="small"
                                scroll={{ y: 300 }}
                                pagination={false}
                                columns={[
                                    { title: '单号', dataIndex: 'orderNo', width: 150 },
                                    { title: '商品', dataIndex: 'productName' },
                                    { title: '供应商变更', render: (_, r) => r.isSupplierChanged ? <span style={{color: '#faad14'}}>{r.oldSupplier} &rarr; {r.newSupplier}</span> : '-' },
                                    { title: '成本变更', render: (_, r) => r.isCostChanged ? <span style={{color: '#faad14'}}>{r.oldCost} &rarr; {r.newCost}</span> : '-' },
                                ]}
                            />
                        </>
                    )}

                    {importSummary.errors.length > 0 && (
                        <>
                            <Divider style={{ borderColor: '#ffccc7', color: '#f5222d' }}>失败记录 ({importSummary.errors.length})</Divider>
                            <Table
                                dataSource={importSummary.errors}
                                size="small"
                                scroll={{ y: 200 }}
                                pagination={false}
                                rowKey={(r) => r.rowInfo.orderNo}
                                columns={[
                                    { title: '单号', dataIndex: ['rowInfo', 'orderNo'], width: 150 },
                                    { title: '失败原因', dataIndex: 'reason', render: (t) => <span style={{color: '#f5222d'}}>{t}</span> },
                                ]}
                            />
                        </>
                    )}
                 </div>
             )}
        </Modal>
    </div>
  );
};

export default PlatformConfirmList;

import React, { useState, useEffect } from 'react';
import { Card, Form, Input, DatePicker, Select, Button, Table, InputNumber, Upload, message, Modal, Space, Typography, Row, Col } from 'antd';
import { PlusOutlined, UploadOutlined, DeleteOutlined, CopyOutlined, SearchOutlined } from '@ant-design/icons';
import { useNavigate } from 'react-router-dom';
import { createPurchaseOrder, generateInboundPurchaseOrder } from '../../services/purchaseOrderService';
import type { PurchaseOrder, PurchaseOrderItem } from '../../services/purchaseOrderService';
import { getWarehouses } from '../../services/warehouseService';
import SupplierSelect from './components/SupplierSelect';
import ProductPoolModal, { FlattenedSku } from './components/ProductPoolModal';
import { getRegionPath } from '../../utils/regionMap';
import dayjs from 'dayjs';
import { trackEvent } from '../../utils/tracker';

const PurchaseOrderCreate: React.FC = () => {
  const [form] = Form.useForm();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [productModalOpen, setProductModalOpen] = useState(false);
  const [warehouses, setWarehouses] = useState<any[]>([]);
  const [selectedSupplierId, setSelectedSupplierId] = useState<number | undefined>();

  // Removed MOCK_PRODUCTS and related search state

  useEffect(() => {
    // Filter only ACTIVE warehouses
    getWarehouses({ statuses: 'ACTIVE' })
      .then(setWarehouses)
      .catch(err => {
        console.error('Failed to load warehouses', err);
        message.error('加载仓库列表失败: ' + (err.response?.data?.message || err.message));
      });
  }, []);

  const handleWarehouseChange = (code: string) => {
    const wh = warehouses.find(w => w.code === code);
    if (wh) {
      const regionPath = getRegionPath(wh.province, wh.city, wh.district);

      // Contact name resolution: managers (fullName) > managers (username) > admins (legacy)
      let contactName = '库管员';
      if (wh.managers && wh.managers.length > 0) {
          contactName = wh.managers[0].fullName || wh.managers[0].username;
      } else if (wh.admins) {
          // Handle legacy admins field (string or array)
          if (Array.isArray(wh.admins)) {
              contactName = wh.admins[0];
          } else if (typeof wh.admins === 'string') {
              // Prevent truncation bug (e.g. "admin"[0] = "a")
              contactName = (wh.admins as string).split(',')[0];
          }
      }

      form.setFieldsValue({
        warehouseRegion: regionPath,
        address: `${regionPath} ${wh.address}`, // Use Chinese region + address detail
        contact: contactName,
        phone: '13800138000' // Placeholder if not available
      });
    }
  };

  const copyAddress = () => {
    const addr = form.getFieldValue('address');
    if (addr) {
      navigator.clipboard.writeText(addr);
      message.success('地址已复制');
    }
  };

  const handleProductSelect = (selectedSkus: FlattenedSku[]) => {
    const currentItems = form.getFieldValue('items') || [];
    const newItems: PurchaseOrderItem[] = [];

    // Auto-fill supplier if not selected (using the first item's default supplier)
    if (!selectedSupplierId && selectedSkus.length > 0) {
        const defaultSupId = selectedSkus[0].defaultSupplierId;
        if (defaultSupId) {
            setSelectedSupplierId(defaultSupId);
            form.setFieldsValue({ supplier: defaultSupId });
            message.info('已自动填充默认供应商');
        }
    }

    selectedSkus.forEach(record => {
        // Avoid duplicates based on SKU Code
        if (!currentItems.find((item: any) => item.skuCode === record.skuCode)) {
            newItems.push({
                productId: record.productId,
                productName: record.productName,
                skuCode: record.skuCode,
                spec: record.specName,
                quantity: 1,
                unitPrice: record.costPrice,
            });
        }
    });

    if (newItems.length === 0 && selectedSkus.length > 0) {
        message.warning('所选商品已在列表中');
    } else {
        const updatedItems = [...currentItems, ...newItems];
        form.setFieldsValue({
            items: updatedItems
        });
        message.success(`已添加 ${newItems.length} 个商品`);
    }

    setProductModalOpen(false);
  };

  const onValuesChange = (changedValues: any, allValues: any) => {
      if (changedValues.supplier) {
          setSelectedSupplierId(changedValues.supplier);
      }
  };

  const onFinish = async (values: any) => {
    // 1. Critical Frontend Validation: Prevent submission with empty items
    if (!values.items || values.items.length === 0) {
        message.error('请至少选择一件商品');
        // Operation Log: Record abnormal click behavior
        trackEvent({
            category: 'PurchaseOrder',
            action: 'CreateBlocked',
            label: 'NoItemsSelected',
            user: values.contact || 'unknown'
        });
        return;
    }

    // 2. Secondary Validation: Ensure items have valid Product IDs and Quantities
    const validItems = values.items.filter((item: any) => item.productId && item.quantity > 0);

    if (validItems.length === 0) {
        message.error('所选商品数据无效（缺少ID或数量），请重新选择');
        trackEvent({
            category: 'PurchaseOrder',
            action: 'CreateBlocked',
            label: 'InvalidItems',
            detail: 'Missing ID or Quantity'
        });
        return;
    }

    setLoading(true);
    try {
      const wh = warehouses.find(w => w.code === values.warehouseCode);

      // Split Logic: One PO per Item (Spec) - Preserving business rule from original file
      const promises = validItems.map(async (item: any) => {
          // validItems already filtered, but safe to keep strict typing
          const totalAmount = item.quantity * item.unitPrice;

          const newPO: Partial<PurchaseOrder> = {
            // let backend generate ID and OrderNo
            supplierId: values.supplier, 
                  // supplierName will be handled by backend or derived
                  deliveryDate: dayjs(values.expectedArrivalDate).format('YYYY-MM-DD'),
                  type: 'INBOUND', 
                  items: [{
                productId: item.productId,
                productName: item.productName,
                skuCode: item.skuCode,
                quantity: item.quantity,
                unitPrice: item.unitPrice,
                totalPrice: totalAmount,
                spec: item.spec
            }],
            status: 'PENDING',
            totalAmount: totalAmount,
            attachments: JSON.stringify(values.attachments?.fileList?.map((f: any) => f.name) || []),
            warehouseId: wh?.id,
            warehouseName: wh?.name,
            contactName: values.contact,
            contactPhone: values.phone,
            province: wh?.province,
            city: wh?.city,
            district: wh?.district,
            detailAddress: wh?.address,
            // Add other fields as necessary
          };
          return generateInboundPurchaseOrder(newPO);
      });

      await Promise.all(promises);

      message.success('入库采购单已生成');
      navigate('/supply-chain/purchase-order');
    } catch (error: any) {
      console.error(error);
      const errorMsg = error.response?.data?.message || error.message || '未知错误';
      message.error(`创建失败: ${errorMsg}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: 24 }}>
      <Card title="新增采购单" variant="borderless">
        <Form
          form={form}
          layout="vertical"
          onFinish={onFinish}
          onValuesChange={onValuesChange}
          initialValues={{ items: [] }}
        >
          <Card type="inner" title="基本信息" style={{ marginBottom: 24 }}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 24 }}>
              <Form.Item name="supplier" label="供应商" rules={[{ required: true }]}>
                <SupplierSelect />
              </Form.Item>
              <Form.Item name="expectedArrivalDate" label="预计到货日期" rules={[{ required: true }]}>
                <DatePicker style={{ width: '100%' }} />
              </Form.Item>
              {/* Project field removed as it was hardcoded and no service exists */}
              <Form.Item name="warehouseCode" label="入库仓库" rules={[{ required: true }]}>
                <Select 
                    placeholder="选择入库分仓"
                    options={warehouses.map(w => ({ label: w.name, value: w.code }))}
                    onChange={handleWarehouseChange}
                />
              </Form.Item>
              <Form.Item name="warehouseRegion" label="分库所在地区" rules={[{ required: true, message: '请选择仓库以获取地区信息' }]}>
                 <Input readOnly placeholder="选择仓库后自动显示" style={{ background: '#f5f5f5' }} />
              </Form.Item>
              <Form.Item name="address" label="收货地址">
                 <Input suffix={<CopyOutlined onClick={copyAddress} style={{ cursor: 'pointer' }} />} />
              </Form.Item>
              <Form.Item name="contact" label="联系人">
                 <Input />
              </Form.Item>
              <Form.Item name="phone" label="联系电话">
                 <Input />
              </Form.Item>
              <Form.Item 
                name="attachments" 
                label="附件"
                valuePropName="fileList"
                getValueFromEvent={(e: any) => {
                  if (Array.isArray(e)) {
                    return e;
                  }
                  return e?.fileList;
                }}
              >
                <Upload beforeUpload={() => false}>
                  <Button icon={<UploadOutlined />}>上传报价单/合同</Button>
                </Upload>
              </Form.Item>
            </div>
          </Card>

          <Card type="inner" title="商品明细 (提交后将按规格自动拆分为多个采购单)" style={{ marginBottom: 24 }} extra={
            <Button type="dashed" onClick={() => setProductModalOpen(true)} icon={<PlusOutlined />}>
              批量添加商品
            </Button>
          }>
            <Form.List name="items">
              {(fields, { remove }) => (
                <Table
                  dataSource={fields}
                  pagination={false}
                  rowKey="key"
                  columns={[
                    {
                      title: '商品名称',
                      dataIndex: 'name',
                      render: (_, field) => {
                        const { key, ...restField } = field;
                        return (
                          <>
                            <Form.Item key={key} {...restField} name={[field.name, 'productName']} style={{ marginBottom: 0 }}>
                              <Input readOnly variant="borderless" />
                            </Form.Item>
                            {/* Hidden fields to ensure these values are included in onFinish */}
                            <Form.Item key={`${key}-productId`} {...restField} name={[field.name, 'productId']} hidden>
                              <Input />
                            </Form.Item>
                            <Form.Item key={`${key}-skuCode`} {...restField} name={[field.name, 'skuCode']} hidden>
                              <Input />
                            </Form.Item>
                          </>
                        );
                      },
                    },
                    {
                      title: '规格',
                      dataIndex: 'spec',
                      render: (_, field) => {
                        const { key, ...restField } = field;
                        return (
                          <Form.Item key={key} {...restField} name={[field.name, 'spec']} style={{ marginBottom: 0 }}>
                            <Input readOnly variant="borderless" />
                          </Form.Item>
                        );
                      },
                    },
                    {
                      title: '采购数量',
                      dataIndex: 'quantity',
                      width: 150,
                      render: (_, field) => {
                        const { key, ...restField } = field;
                        return (
                          <Form.Item
                            key={key}
                            {...restField}
                            name={[field.name, 'quantity']}
                            rules={[{ required: true, message: '请输入数量' }]}
                            style={{ marginBottom: 0 }}
                          >
                            <InputNumber min={1} precision={0} style={{ width: '100%' }} />
                          </Form.Item>
                        );
                      },
                    },
                    {
                      title: '单价(元)',
                      dataIndex: 'unitPrice',
                      width: 150,
                      render: (_, field) => {
                        const { key, ...restField } = field;
                        return (
                          <Form.Item
                            key={key}
                            {...restField}
                            name={[field.name, 'unitPrice']}
                            rules={[{ required: true, message: '请输入单价' }]}
                            style={{ marginBottom: 0 }}
                          >
                            <InputNumber min={0} precision={2} style={{ width: '100%' }} />
                          </Form.Item>
                        );
                      },
                    },
                    {
                      title: '小计',
                      key: 'subtotal',
                      render: (_, field) => {
                          const qty = form.getFieldValue(['items', field.name, 'quantity']) || 0;
                          const cost = form.getFieldValue(['items', field.name, 'unitPrice']) || 0;
                          return (qty * cost).toFixed(2);
                      }
                    },
                    {
                      title: '操作',
                      width: 80,
                      render: (_, field) => (
                        <Button type="text" danger icon={<DeleteOutlined />} onClick={() => remove(field.name)} />
                      ),
                    },
                  ]}
                />
              )}
            </Form.List>
          </Card>

          <Form.Item shouldUpdate={(prev, curr) => prev.items !== curr.items} style={{ marginBottom: 0 }}>
            {() => {
              const items = form.getFieldValue('items') || [];
              const hasItems = items.length > 0;
              return (
                <Space>
                   <Button 
                     type="primary" 
                     htmlType="submit" 
                     loading={loading}
                     disabled={!hasItems}
                     title={!hasItems ? "请至少选择一件商品" : ""}
                   >
                     生成入库采购单
                   </Button>
                   {!hasItems && <span style={{ color: '#ff4d4f', fontSize: '12px' }}>* 请先选择商品</span>}
                   <Button onClick={() => navigate('/supply-chain/purchase-order')}>取消</Button>
                </Space>
              );
            }}
          </Form.Item>
        </Form>

        <ProductPoolModal
          open={productModalOpen}
          onCancel={() => setProductModalOpen(false)}
          onOk={handleProductSelect}
        />
      </Card>
    </div>
  );
};

