     poNo: 'C231027001001',
     bizType: '订单采购',
     bizNo: 'SO202310270001',
     supplier: '晨光文具',
     status: '待发货',
     createTime: '2023-10-27 10:00:00',
     purchaser: '张三',
     receiver: '李四',
     phone: '13800138000',
     address: '上海市浦东新区张江高科...',
     expectTime: '2023-10-30',
     remarks: '请务必在月底前送达，急用。',
     // Logistics Info (Optional fields mocked)
     shipCompany: '',
     shipNo: '',
     shipAuxCode: '',
     deliverer: '',
     contact: '',
     plateNo: '',
     shipTime: '',
     // Fee Info
     cost: 1800.00,
     freight: 0.00,
     refundAmt: 0.00,
     adjustDiff: 0.00,
     dueAmt: 1800.00,
     paidAmt: 0.00,
  });

  useEffect(() => {
    const fetchOrder = async () => {
        if (id) {
            try {
                const order = await getPurchaseOrderById(Number(id));
                if (order) {
                    // Merge real data with display structure
                    setOrderInfo((prev: any) => ({
                        ...prev,
                        poNo: order.orderNo, // Assuming orderNo is the field
                        supplier: order.supplierName,
                        status: order.status === 'SHIPPED' ? '已发货' : (order.status === 'CONFIRMED' ? '待发货' : order.status),
                        items: order.items,
                        // If shipped, populate logistics
                        shipCompany: order.logisticsCompany,
                        shipNo: order.trackingNumber,
                        freight: 0, // order.logisticsFee not in interface yet
                        shipTime: order.shippedAt
                    }));

                    // Fetch tracks
                    if (order.orderNo) {
                        const trackList = await getLogisticsTracks(order.orderNo);
                        setTracks(trackList);
