                const response = await fetch(`/api/purchase-orders/${currentShipOrder.key}/ship`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' }
                });

                if (!response.ok) {
                    throw new Error('发货失败');
                }

                setOrders(orders.map(o => o.key === currentShipOrder.key ? { ...o, status: 'Shipped' } : o));
                // Create Settlement logic remains same...
            } catch (e) {
                message.error({ content: '发货操作失败', key: 'ship' });
                return;
            }
        } else if (selectedRowKeys.length > 0) {
            // Batch ship logic
            try {
                const response = await fetch(`/api/purchase-orders/batch-ship`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(selectedRowKeys)
                });

                if (!response.ok) {
                    throw new Error('批量发货失败');
                }

                setOrders(orders.map(o => selectedRowKeys.includes(o.key) ? { ...o, status: 'Shipped' } : o));
