            exportParams.endDate = values.orderTime[1].format('YYYY-MM-DD');
            delete exportParams.orderTime;
        }

        const res = await getPurchaseOrders(exportParams);
        const pendingOrders = res.records;

        if (pendingOrders.length === 0) {
            message.warning({ content: '没有符合条件的待处理采购单', key: 'export_shipment' });
            return;
        }

        const data = pendingOrders.map(o => ({
            orderNo: o.orderNo || '',
            supplier: o.supplierName || o.supplier?.name || '',
            products: o.items?.map(i => `${i.productName} (${i.spec || ''})`).join(', ') || '',
            quantity: o.items?.reduce((sum, i) => sum + i.quantity, 0) || 0,
            address: `${o.province || ''}${o.city || ''}${o.district || ''}${o.detailAddress || ''}`,
            contact: o.contactName || '',
            phone: o.contactPhone || ''
        }));

        if (exportFormat === 'excel') {
            const ws = XLSX.utils.json_to_sheet(data.map(item => ({
                '采购单号': item.orderNo,
                '供应商': item.supplier,
                '商品信息': item.products,
                '数量': item.quantity,
                '收货地址': item.address,
                '联系人': item.contact,
                '联系电话': item.phone
            })));
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, "发货单");
            XLSX.writeFile(wb, `发货单_${new Date().toISOString().slice(0,10)}.xlsx`);
        } else {
            const doc = new jsPDF();
            // Basic PDF generation - note: Chinese characters may not render correctly without a custom font
            (autoTable as any)(doc, {
                head: [['Order No', 'Supplier', 'Products', 'Qty', 'Address', 'Contact', 'Phone']],
                body: data.map(item => [
                    item.orderNo, 
                    item.supplier, 
                    item.products, 
                    item.quantity, 
                    item.address, 
                    item.contact, 
                    item.phone
                ]),
            });
            doc.save(`shipments_${new Date().toISOString().slice(0,10)}.pdf`);
        }

        message.success({ content: '导出成功', key: 'export_shipment' });
