          <Form.Item label="选择已启用品牌" required help="支持多选，可输入品牌名称搜索">
            <Select
              mode="multiple"
              showSearch
              placeholder="请选择品牌"
              style={{ width: '100%' }}
              filterOption={false}
              onSearch={handleSearchBrand}
              notFoundContent={brandLoading ? <Spin size="small" /> : null}
              value={selectedBrandIds}
              onChange={(values, options) => {
                  setSelectedBrandIds(values);
                  if (Array.isArray(options)) {
                      const newObjects = values.map(id => {
                          const existing = selectedBrandObjects.find(o => o.id === id);
                          if (existing) return existing;
                          const fromList = brandList.find(b => b.id === id);
                          const fromOption = (options.find((o: any) => o.value === id) as any)?.data;
                          return fromList || fromOption;
                      }).filter(Boolean);
                      setSelectedBrandObjects(newObjects);
                  }
              }}
              options={[...brandList, ...selectedBrandObjects]
                  .filter((v, i, a) => a.findIndex(t => t.id === v.id) === i)
                  .map(b => ({
                      value: b.id,
                      label: b.name,
                      data: b
                  }))}
            />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
};

export default SupplierDetail;

import React, { useState, useEffect } from 'react';
import { Upload, Button, List, Image, message, Modal, Space, Popconfirm, Form, Input, Table, Tag, Row, Col } from 'antd';
import { UploadOutlined, DeleteOutlined, FileOutlined, EyeOutlined, DownloadOutlined, EditOutlined, HistoryOutlined, CloudUploadOutlined } from '@ant-design/icons';
import type { UploadFile, UploadProps } from 'antd/es/upload/interface';
import request from '../../utils/request';

interface SupplierFileDTO {
    id: number | string; // Allow string for temp IDs if needed, though backend returns null/0 for temp? No, temp upload returns DTO with no ID usually? 
    // Backend temp upload returns DTO. 
    // Let's assume ID might be null or we use storedFileName as key for temp files.
    originalFileName: string;
    storedFileName: string;
    fileType: string;
    fileSize: number;
    uploadTime: string;
    uploader?: string;
    description: string;
    url: string;
    version: number;
    groupId: string;
    isLatest: boolean;
    category: string;
}

interface SupplierFileManagerProps {
    supplierId?: number;
    category: 'QUALIFICATION' | 'CONTRACT';
    isView: boolean;
    onFilesChange?: (files: SupplierFileDTO[]) => void;
    apiPrefix?: string;
}

const SupplierFileManager: React.FC<SupplierFileManagerProps> = ({ supplierId, category, isView, onFilesChange, apiPrefix = '/supplier-files' }) => {
    const [fileList, setFileList] = useState<SupplierFileDTO[]>([]);
    const [loading, setLoading] = useState(false);
    const [previewOpen, setPreviewOpen] = useState(false);
    const [previewImage, setPreviewImage] = useState('');
    const [previewTitle, setPreviewTitle] = useState('');

    const [editOpen, setEditOpen] = useState(false);
    const [editingFile, setEditingFile] = useState<SupplierFileDTO | null>(null);
    const [editForm] = Form.useForm();

    // Version Control States
    const [updateVersionOpen, setUpdateVersionOpen] = useState(false);
    const [updatingFile, setUpdatingFile] = useState<SupplierFileDTO | null>(null);

    const [historyOpen, setHistoryOpen] = useState(false);
    const [historyList, setHistoryList] = useState<SupplierFileDTO[]>([]);
    const [historyLoading, setHistoryLoading] = useState(false);

    const addTokenToUrl = (url: string) => {
        const token = localStorage.getItem('token');
        if (!token) return url;
        return `${url}${url.includes('?') ? '&' : '?'}token=${token}`;
    };

    const fetchFiles = async () => {
        if (!supplierId) return;
        try {
            const res: any = await request.get(`${apiPrefix}/${supplierId}`, {
                params: { category }
            });
            const filesWithToken = (res || []).map((file: SupplierFileDTO) => ({
                ...file,
                url: addTokenToUrl(file.url)
            }));
            setFileList(filesWithToken);
            onFilesChange?.(filesWithToken);
        } catch (error: any) {
            console.error('Failed to fetch files:', error);
            if (error.response) {
                const { status } = error.response;
                if (status === 404) {
                    message.error('文件服务不可用(404)：请管理员检查部署或重新创建默认目录');
                } else if (status === 401) {
                    message.error('认证失败(401)：请重新登录');
                } else if (status === 500) {
                    message.error('服务器内部错误(500)：请联系管理员');
                } else {
                    message.error(`获取文件列表失败: ${status}`);
                }
            } else {
                message.error('网络错误或服务不可达');
            }
        }
    };

    useEffect(() => {
        if (supplierId) {
            fetchFiles();
        } else {
            setFileList([]); // Reset for new supplier
            onFilesChange?.([]);
        }
    }, [supplierId, category]);

    const beforeUpload = (file: UploadFile) => {
        const isLt50M = (file.size || 0) / 1024 / 1024 < 50;
        if (!isLt50M) {
            message.error('文件大小不能超过 50MB!');
            return Upload.LIST_IGNORE;
        }
        return true;
    };

    const handleUpload: UploadProps['customRequest'] = async (options) => {
        const { file, onSuccess, onError } = options;
        const formData = new FormData();
        formData.append('file', file as File);
        formData.append('category', category);

        try {
            setLoading(true);
            let newFile: SupplierFileDTO;

            if (supplierId) {
                // Permanent upload
                await request.post(`${apiPrefix}/${supplierId}/upload`, formData);
                message.success('上传成功');
                fetchFiles(); // Reload list
                onSuccess?.("ok");
            } else {
                // Temp upload
                const res: any = await request.post(`${apiPrefix}/temp/upload`, formData);
                console.log('Temp file uploaded:', res);
                newFile = {
                    ...res,
                    url: addTokenToUrl(res.url)
                };
                message.success('上传成功');
                const newList = [...fileList, newFile];
                setFileList(newList);
                onFilesChange?.(newList);
                onSuccess?.("ok");
            }
        } catch (error: any) {
            console.error('Upload error details:', error);
            const errorMsg = error.response?.data?.message || error.message || '上传失败';

            if (error.response) {
                const { status } = error.response;
                if (status === 404) {
                     message.error('上传失败(404)：请管理员检查上传服务或默认目录是否创建');
                } else if (status === 401) {
                     message.error('上传失败(401)：会话已过期，请重新登录');
                } else if (status === 413) {
                     message.error('上传失败(413)：文件大小超过限制(50MB)');
                } else if (status === 500) {
                     message.error('上传失败(500)：服务器内部错误');
                } else {
                     message.error(`上传失败: ${errorMsg}`);
                }
            } else {
                message.error(`上传失败: ${errorMsg}`);
            }
            onError?.(error as Error);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (file: SupplierFileDTO) => {
        try {
            if (supplierId && file.id) {
                // Permanent delete
                await request.delete(`${apiPrefix}/${file.id}`);
                message.success('删除成功');
                fetchFiles();
            } else {
                // Temp delete (remove from local list)
                // Use storedFileName as unique identifier for temp files if id is missing
                const newList = fileList.filter(f => f.storedFileName !== file.storedFileName);
                setFileList(newList);
                onFilesChange?.(newList);
                message.success('删除成功');
            }
        } catch (error) {
            message.error('删除失败');
        }
    };

    const isImage = (fileName: string) => {
        return /\.(jpg|jpeg|png|gif)$/i.test(fileName);
    };

    const handlePreview = (file: SupplierFileDTO) => {
        if (isImage(file.originalFileName)) {
            setPreviewImage(file.url);
            setPreviewTitle(file.originalFileName);
            setPreviewOpen(true);
        } else {
            window.open(file.url, '_blank');
        }
    };

    const handleEdit = (file: SupplierFileDTO) => {
        setEditingFile(file);
        editForm.setFieldsValue({ description: file.description });
        setEditOpen(true);
    };

    const handleSaveEdit = async () => {
        try {
            const values = await editForm.validateFields();
            if (editingFile) {
                if (supplierId && editingFile.id) {
                    await request.put(`${apiPrefix}/${editingFile.id}`, null, {
                        params: { description: values.description }
                    });
                    message.success('更新成功');
                    fetchFiles();
                } else {
                    // Update local temp file
                    const newList = fileList.map(f => {
                        if (f.storedFileName === editingFile.storedFileName) {
                            return { ...f, description: values.description };
                        }
                        return f;
                    });
                    setFileList(newList);
                    onFilesChange?.(newList);
                    message.success('更新成功');
                }
                setEditOpen(false);
            }
        } catch (error) {
            console.error(error);
            message.error('更新失败');
        }
    };

    // Version Control Handlers
    const handleOpenUpdateVersion = (file: SupplierFileDTO) => {
        setUpdatingFile(file);
        setUpdateVersionOpen(true);
    };

    const handleUpdateVersion: UploadProps['customRequest'] = async (options) => {
        if (!updatingFile) return;
        const { file, onSuccess, onError } = options;
        const formData = new FormData();
        formData.append('file', file as File);
        // formData.append('description', 'Updated version'); // Could add description field

        try {
            setLoading(true);
            await request.post(`${apiPrefix}/${updatingFile.id}/version`, formData, {
                headers: { 'Content-Type': 'multipart/form-data' },
            });
            message.success('版本更新成功');
            setUpdateVersionOpen(false);
            fetchFiles();
            onSuccess?.("ok");
        } catch (error) {
            message.error('版本更新失败');
            onError?.(error as Error);
        } finally {
            setLoading(false);
        }
    };

    const handleViewHistory = async (file: SupplierFileDTO) => {
        try {
            setHistoryLoading(true);
            setHistoryOpen(true);
            const res: any = await request.get(`${apiPrefix}/history/${file.groupId}`);
            const filesWithToken = (res || []).map((file: SupplierFileDTO) => ({
                ...file,
                url: addTokenToUrl(file.url)
            }));
            setHistoryList(filesWithToken);
        } catch (error) {
            message.error('获取历史版本失败');
        } finally {
            setHistoryLoading(false);
        }
    };

    const historyColumns = [
        { title: '版本', dataIndex: 'version', key: 'version', render: (v: number) => `V${v}` },
        { title: '文件名', dataIndex: 'originalFileName', key: 'originalFileName' },
        { title: '上传时间', dataIndex: 'uploadTime', key: 'uploadTime', render: (t: string) => new Date(t).toLocaleString() },
        { title: '上传者', dataIndex: 'uploader', key: 'uploader' },
        { 
            title: '操作', 
            key: 'action',
            render: (_: any, record: SupplierFileDTO) => (
                <Space>
                    <Button type="link" size="small" onClick={() => handlePreview(record)}>预览</Button>
                    <Button type="link" size="small" href={record.url} target="_blank">下载</Button>
                </Space>
            )
        }
    ];

    return (
        <div>
            {!isView && (
                <div style={{ marginBottom: 16, display: 'flex', justifyContent: 'space-between' }}>
                    <Upload
                        customRequest={handleUpload}
                        showUploadList={false}
                        accept={category === 'QUALIFICATION' ? ".jpg,.jpeg,.png,.pdf" : ".pdf,.doc,.docx,.xls,.xlsx"}
                    >
                        <Button icon={<UploadOutlined />} loading={loading}>
                            上传文件
                        </Button>
                    </Upload>
                </div>
            )}

            <Row gutter={[16, 16]} style={{ marginTop: 16 }}>
                {fileList.map((item, index) => (
                    <Col xs={24} sm={12} md={6} lg={6} xl={6} xxl={6} key={item.id || item.storedFileName || index}>
                        <div style={{ border: '1px solid #d9d9d9', borderRadius: 4, padding: 8, textAlign: 'center', position: 'relative' }}>
                            <Tag color="blue" style={{ position: 'absolute', top: 5, right: 5 }}>V{item.version}</Tag>
                            <div style={{ height: 100, display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: 8, cursor: 'pointer' }} onClick={() => handlePreview(item)}>
                                {isImage(item.originalFileName) ? (
                                    <img src={item.url} alt={item.originalFileName} style={{ maxWidth: '100%', maxHeight: '100%', objectFit: 'contain' }} />
                                ) : (
                                    <FileOutlined style={{ fontSize: 48, color: '#1890ff' }} />
                                )}
                            </div>
                            <div style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', marginBottom: 8 }} title={item.originalFileName}>
                                {item.originalFileName}
                            </div>
                            <Space wrap style={{ justifyContent: 'center' }}>
                                <Button type="text" icon={<EyeOutlined />} size="small" onClick={() => handlePreview(item)} title="预览" />
                                <Button type="text" icon={<DownloadOutlined />} size="small" href={item.url} target="_blank" title="下载" />
                                <Button type="text" icon={<HistoryOutlined />} size="small" onClick={() => handleViewHistory(item)} title="历史版本" />
                                {!isView && (
                                    <>
                                        {supplierId && (
                                            <Button type="text" icon={<CloudUploadOutlined />} size="small" onClick={() => handleOpenUpdateVersion(item)} title="更新版本" />
                                        )}
                                        <Button type="text" icon={<EditOutlined />} size="small" onClick={() => handleEdit(item)} title="编辑信息" />
                                        <Popconfirm title="确定删除吗?" onConfirm={() => handleDelete(item)}>
                                            <Button type="text" danger icon={<DeleteOutlined />} size="small" title="删除" />
                                        </Popconfirm>
                                    </>
                                )}
                            </Space>
                        </div>
                        <div style={{ fontSize: 12, color: '#888', textAlign: 'center', marginTop: 4 }}>
                           {item.description || '-'}
                        </div>
                    </Col>
                ))}
            </Row>

            <Modal
                open={previewOpen}
                title={previewTitle}
                footer={null}
                onCancel={() => setPreviewOpen(false)}
                width={800}
            >
                <img alt="example" style={{ width: '100%' }} src={previewImage} />
            </Modal>

            <Modal
                open={editOpen}
                title="编辑文件信息"
                onOk={handleSaveEdit}
                onCancel={() => setEditOpen(false)}
            >
                <Form form={editForm} layout="vertical">
                    <Form.Item name="description" label="文件描述">
                        <Input.TextArea rows={4} maxLength={200} showCount />
                    </Form.Item>
                </Form>
            </Modal>

            <Modal
                open={updateVersionOpen}
                title={`更新版本: ${updatingFile?.originalFileName}`}
                footer={null}
                onCancel={() => setUpdateVersionOpen(false)}
            >
                <div style={{ textAlign: 'center', padding: 20 }}>
                    <p>上传新文件将作为 V{(updatingFile?.version || 0) + 1} 版本保存，旧版本将保留在历史记录中。</p>
                    <Upload
                        beforeUpload={beforeUpload}
                        customRequest={handleUpdateVersion}
                        showUploadList={false}
                        accept={category === 'QUALIFICATION' ? ".jpg,.jpeg,.png,.pdf" : ".pdf,.doc,.docx,.xls,.xlsx"}
                    >
                        <Button type="primary" icon={<CloudUploadOutlined />} loading={loading}>
                            选择并上传新版本
                        </Button>
                    </Upload>
                </div>
            </Modal>

            <Modal
                open={historyOpen}
                title="文件历史版本"
                footer={null}
                onCancel={() => setHistoryOpen(false)}
                width={700}
            >
                <Table 
                    dataSource={historyList} 
                    columns={historyColumns} 
                    rowKey="id" 
                    loading={historyLoading}
                    pagination={{ pageSize: 5 }}
                />
            </Modal>
        </div>
    );
};

export default SupplierFileManager;

import React, { useState, useEffect } from 'react';
import { Table, Button, Input, Select, Space, Tag, message, Row, Col, Form, Tooltip, Dropdown, Modal } from 'antd';
import type { ColumnsType } from 'antd/es/table';
import { PlusOutlined, EditOutlined, StopOutlined, CheckCircleOutlined, EyeOutlined, ExportOutlined, AccountBookOutlined, DownOutlined, BankOutlined, DeleteOutlined, WarningOutlined } from '@ant-design/icons';
import { useNavigate, useLocation } from 'react-router-dom';
import PageDoc from '../../components/PageDoc';
import { useExport } from '../../utils/exportUtils';
import { getSuppliers, SupplierDTO, deleteAllSuppliers } from '../../services/supplierService';
import request from '../../utils/request';

interface SupplierDataType {
  key: string;
  supplierName: string;
  supplierId: string;
  contact: string;
  brands: string[];
  contactInfo: string;
  purchaserInfo: string;
  status: 'Enabled' | 'Disabled';
  createTime: string;
  coopEndTime: string;
  settlementType?: 'Cash' | 'Prepayment' | 'Period';
  settlementCycle?: string;
  orgCode?: string;
  purchaserId?: number;
}

const SupplierList: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [showExpiring, setShowExpiring] = useState(false);
  const [suppliers, setSuppliers] = useState<SupplierDataType[]>([]);
  const [pagination, setPagination] = useState({ current: 1, pageSize: 10, total: 0 });
  const [userOptions, setUserOptions] = useState<{label: string, value: number}[]>([]);

  // Fetch users for purchaser filter
  useEffect(() => {
    const fetchUsers = async () => {
        try {
            const res: any = await request.get('/users/list');
            if (res && res.content) {
                setUserOptions(res.content.map((u: any) => ({ label: u.username, value: u.id })));
            }
        } catch (e) {
            console.error(e);
        }
    };
    fetchUsers();
  }, []);

  const fetchSuppliers = async (page = 1, size = 10) => {
    setLoading(true);
    try {
      const values = form.getFieldsValue();
      const res = await getSuppliers({ 
        page: page - 1, 
        size,
        name: values.supplierName,
        settlementType: values.settlementType,
        settlementPeriod: values.settlementPeriod,
        purchaserId: values.purchaserId,
        contactInfo: values.contactInfo,
        expiringSoon: showExpiring
      });
      const mappedData: SupplierDataType[] = res.content.map((item: SupplierDTO) => ({
        key: item.id.toString(),
        supplierName: item.name,
        supplierId: item.supplierNo,
        contact: item.contactPerson,
        brands: item.brandNames || [],
        contactInfo: `${item.contactPhone || ''} / ${item.address || ''}`,
        purchaserInfo: item.purchaserName || '-',
        status: item.status === 'ACTIVE' ? 'Enabled' : 'Disabled',
        createTime: item.createdAt,
        coopEndTime: item.coopEndTime ? item.coopEndTime.substring(0, 10) : '-',
        settlementType: item.settlementType === 'PREPAYMENT' ? 'Prepayment' : item.settlementType === 'CASH' ? 'Cash' : 'Period',
        settlementCycle: item.settlementPeriod === 1 ? 'Daily' :
                         item.settlementPeriod === 7 ? 'Weekly' :
                         item.settlementPeriod === 30 ? 'Monthly' : 
                         item.settlementPeriod === 90 ? 'Quarterly' :
                         item.settlementPeriod ? `${item.settlementPeriod} Days` : '-',
        orgCode: item.orgCode,
        purchaserId: item.purchaserId
      }));
      setSuppliers(mappedData);
      setPagination({ ...pagination, current: page, total: res.totalElements });
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSuppliers(pagination.current, pagination.pageSize);
  }, [pagination.current, pagination.pageSize, location.key, showExpiring]);

  const handleStatusChange = (key: string, newStatus: 'Enabled' | 'Disabled') => {
    // TODO: Call backend API to update status
    const newSuppliers = suppliers.map(item => 
      item.key === key ? { ...item, status: newStatus } : item
    );
    setSuppliers(newSuppliers);
    message.success(`供应商状态已更新为 ${newStatus === 'Enabled' ? '已启用' : '已禁用'}`);
  };

  const handleDeleteAll = () => {
      Modal.confirm({
          title: '确认清空数据',
          content: '确定要删除所有供应商数据吗？此操作不可恢复！',
          okText: '确认删除',
          okType: 'danger',
          cancelText: '取消',
          onOk: async () => {
              try {
                  await deleteAllSuppliers();
                  message.success('所有供应商数据已清空');
                  fetchSuppliers(1, pagination.pageSize);
              } catch (e) {
                  message.error('清空数据失败');
              }
          }
      });
  };

  // Filtered data is now handled by backend via showExpiring state triggering fetch
  const filteredData = suppliers;

  const { handleExport, exporting, progress } = useExport<SupplierDataType>({
    filenamePrefix: '供应商列表',
    fetchData: () => filteredData,
    columns: [
      { title: '供应商ID', dataIndex: 'supplierId' },
      { title: '供应商全称', dataIndex: 'supplierName' },
      { title: '主要联系人', dataIndex: 'contact' },
      { title: '联系电话', dataIndex: 'contactInfo', render: (val) => val.split(' / ')[0] || val },
      { title: '采购员信息', dataIndex: 'purchaserInfo' },
      { title: '状态', dataIndex: 'status', render: (val) => val === 'Enabled' ? '已启用' : '已禁用' },
      { title: '创建时间', dataIndex: 'createTime' },
      { title: '合作结束时间', dataIndex: 'coopEndTime' },
    ]
  });

  const columns: ColumnsType<SupplierDataType> = [
    { title: '供应商ID', dataIndex: 'supplierId', key: 'supplierId', width: 100 },
    { title: '供应商名称', dataIndex: 'supplierName', key: 'supplierName' },
    {
      title: '联系人信息',
      key: 'contactInfo',
      render: (_, record) => {
         const phone = record.contactInfo.split(' / ')[0];
         return `${record.contact} (${phone})`;
      }
    },
    {
      title: '合作品牌',
      dataIndex: 'brands',
      key: 'brands',
      render: (brands: string[]) => (
        <Space wrap>
          {brands && brands.map((b) => <Tag key={b}>{b}</Tag>)}
        </Space>
      ),
    },
    { title: '采购负责人', dataIndex: 'purchaserInfo', key: 'purchaserInfo' },
    {
      title: '结算类型',
      dataIndex: 'settlementType',
      key: 'settlementType',
      width: 100,
      render: (type) => (
        <Tag color={type === 'Prepayment' ? 'gold' : 'blue'}>
          {type === 'Prepayment' ? '预付' : '现付'}
        </Tag>
      ),
    },
    {
      title: '结算周期',
      dataIndex: 'settlementCycle',
      key: 'settlementCycle',
      width: 100,
      render: (text, record) => {
        if (record.settlementType === 'Prepayment') {
           return null;
        }
        const cycleMap: Record<string, string> = {
           'Monthly': '月结',
           'Weekly': '周结',
           'Quarterly': '季结',
           'Daily': '日结'
        };
        return cycleMap[text] || text || '-';
      }
    },
    {
      title: '状态',
      dataIndex: 'status',
      key: 'status',
      width: 80,
      render: (status) => (
        <Tag color={status === 'Enabled' ? 'success' : 'error'}>
          {status === 'Enabled' ? '已启用' : '已禁用'}
        </Tag>
      ),
    },
    { 
        title: '合作截止时间', 
        dataIndex: 'coopEndTime', 
        key: 'coopEndTime', 
        width: 120,
        render: (text) => {
             // Check if expiring soon logic needed for display
             if (text === '-') return text;
             const endDate = new Date(text);
             const today = new Date();
             const diffTime = endDate.getTime() - today.getTime();
             const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
             const isExpiring = diffDays <= 30 && diffDays >= 0;
             return isExpiring ? <Tag color="error" icon={<WarningOutlined />}>{text} (临期)</Tag> : text;
        }
    },
    {
      title: '操作',
      key: 'action',
      width: 120,
      render: (_, record) => {
        const items = [
          {
            key: 'view',
            label: '查看',
            icon: <EyeOutlined />,
            onClick: () => navigate(`/supply-chain/supplier/view/${record.key}`),
          },
          ...(record.settlementType === 'Prepayment' ? [{
            key: 'prepayment',
            label: '预付款管理',
            icon: <BankOutlined />,
            onClick: () => navigate(`/supply-chain/supplier/prepayment-list/${record.key}`),
          }] : []),
          ...(record.settlementType === 'Prepayment' ? [{
            key: 'log',
            label: '预付款流水',
            icon: <AccountBookOutlined />,
            onClick: () => navigate(`/supply-chain/supplier/prepayment-log/${record.key}`),
          }] : []),
          {
            key: 'edit',
            label: '编辑',
            icon: <EditOutlined />,
            onClick: () => navigate(`/supply-chain/supplier/edit/${record.key}`),
          },
          {
            key: 'status',
            label: record.status === 'Enabled' ? '禁用' : '启用',
            icon: record.status === 'Enabled' ? <StopOutlined /> : <CheckCircleOutlined />,
            danger: record.status === 'Enabled',
            onClick: () => handleStatusChange(record.key, record.status === 'Enabled' ? 'Disabled' : 'Enabled'),
          },
        ];

        return (
          <Dropdown menu={{ items }}>
            <a onClick={(e) => e.preventDefault()}>
              操作 <DownOutlined />
            </a>
          </Dropdown>
        );
      },
    },
  ];

  return (
    <div style={{ background: '#fff', padding: 24, minHeight: 360 }}>
      <PageDoc 
        pageTitle="供应链管理 > 供应商管理"
        description={`供应商管理页面为供应商列表页。

1. **列表字段**：
   - 供应商名称、供应商ID、联系人。
   - 品牌名称（可展示多个）、联系人信息（手机号、地址）、采购负责人信息（姓名、手机号）。
   - **结算类型**（现付/预付）、**结算周期**（仅现付显示）。
   - 供应商状态、创建时间、合作截止时间。
   - 操作列：查看、启用（禁用状态时显示）、禁用（启用状态时显示）、编辑。

2. **数据来源说明**：
   - **品牌信息**：调用[品牌管理]模块数据（更新频率：实时；权限：读取）。
   - **采购负责人**：调用[用户中心/权限系统]数据（更新频率：缓存/实时；权限：读取）。

3. **状态说明**：
   - **已启用**：启用状态供应商可在其他业务操作页面如商品管理、采购订单管理中被选择。
   - **已禁用**：禁用状态不可被选择。

4. **搜索与筛选**：
   - 支持搜索：供应商信息（名称）、品牌信息（模糊搜索/可查可选）、联系人信息（手机号/地址）、采购负责人信息。
   - 支持筛选：创建时间范围、合作截止时间范围、合作状态。

5. **高级功能**：
   - **查看临期供应商**：展示合作截止时间距离当前30天内的供应商列表。
   - **批量导出**：导出所有搜索结果到Excel。
   - **新增供应商**：跳转至新增详情页。

6. **异常处理**：
   - **加载失败**：网络异常时提示错误。
   - **无数据**：筛选无结果时展示空状态。`}
        fields={[
          { name: 'supplierId', type: 'String', length: '32', required: true, unique: true, desc: '供应商ID (SUP+...)' },
          { name: 'supplierName', type: 'String', length: '200', required: true, unique: false, desc: '供应商全称' },
          { name: 'contact', type: 'String', length: '50', required: true, unique: false, desc: '主要联系人' },
          { name: 'phone', type: 'String', length: '20', required: true, unique: false, desc: '联系电话' },
        ]}
      />
      <Form form={form} layout="inline" style={{ marginBottom: 24 }} onFinish={() => fetchSuppliers(1, pagination.pageSize)}>
         <Row gutter={[16, 16]}>
           <Col>
             <Form.Item name="supplierName" label="供应商名称">
                <Input placeholder="请输入" style={{ width: 150 }} />
             </Form.Item>
           </Col>
           <Col>
             <Form.Item name="contactInfo" label="联系人信息">
                <Input placeholder="姓名/电话/邮箱" style={{ width: 150 }} />
             </Form.Item>
           </Col>
           <Col>
             <Form.Item name="purchaserId" label="采购负责人">
                <Select placeholder="请选择" style={{ width: 120 }} allowClear options={userOptions} />
             </Form.Item>
           </Col>
           <Col>
             <Form.Item name="settlementType" label="结算类型">
                <Select placeholder="请选择" style={{ width: 100 }} allowClear>
                   <Select.Option value="PREPAYMENT">预付</Select.Option>
                   <Select.Option value="CASH">现付</Select.Option>
                   <Select.Option value="PERIOD">账期</Select.Option>
                </Select>
             </Form.Item>
           </Col>
           <Col>
             <Form.Item name="settlementPeriod" label="结算周期">
                <Select placeholder="请选择" style={{ width: 100 }} allowClear>
                   <Select.Option value={7}>周结</Select.Option>
                   <Select.Option value={30}>月结</Select.Option>
                   <Select.Option value={90}>季结</Select.Option>
                </Select>
             </Form.Item>
           </Col>
           <Col>
             <Form.Item>
                <Space>
                   <Button type="primary" htmlType="submit">查询</Button>
                   <Button onClick={() => {
                     form.resetFields();
                     fetchSuppliers(1, pagination.pageSize);
                   }}>重置</Button>
                </Space>
             </Form.Item>
           </Col>
         </Row>
      </Form>

      <div style={{ marginBottom: 16, display: 'flex', justifyContent: 'space-between' }}>
         <Space>
            <Button type="primary" icon={<PlusOutlined />} onClick={() => navigate('/supply-chain/supplier/add')}>
               新增供应商
            </Button>
            <Button 
              danger={!showExpiring} 
              type={showExpiring ? 'primary' : 'default'}
              onClick={() => setShowExpiring(!showExpiring)}
              icon={showExpiring ? <CheckCircleOutlined /> : <WarningOutlined />}
            >
              {showExpiring ? '显示全部供应商' : '查看临期供应商'}
            </Button>
         </Space>
         <Space>
            <Button danger icon={<DeleteOutlined />} onClick={handleDeleteAll}>
                清空数据
            </Button>
            <Button icon={<ExportOutlined />} onClick={handleExport} loading={exporting}>
                {exporting ? `导出中 ${progress}%` : '批量导出'}
            </Button>
         </Space>
      </div>

      <Table columns={columns} dataSource={filteredData} scroll={{ x: 1300 }} loading={loading} />
    </div>
  );
};

export default SupplierList;

