};

const SupplierPrepaymentDetail: React.FC = () => {
  const navigate = useNavigate();
  const { id } = useParams();

  const [loading, setLoading] = useState(true);
  const [detail, setDetail] = useState<DetailData | null>(null);
  const [rejectReason, setRejectReason] = useState('');
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);

  useEffect(() => {
    // Simulate API fetch
    setLoading(true);
    setTimeout(() => {
      if (id && MOCK_DB[id]) {
        setDetail({ ...MOCK_DB[id] });
      } else {
        // Fallback or Not Found handling
        // For demo purposes, if ID not found, load a default Pending one or show error
        // Here we default to the Pending one if not found, but ideally we should be strict.
        // Let's create a dynamic default if ID is missing from DB to prevent crash
        setDetail({
            id: id || 'UNKNOWN',
            status: 'Pending',
            businessType: '供应商预付款',
            payer: { name: '我的企业', bank: '招商银行', account: '1234567890' },
            payee: { name: '未知供应商', bank: '未知银行', account: '000000' },
            contact: { name: '未知', phone: '-' },
            amount: { applied: 0, actual: 0, unpaid: 0 },
            attachments: [],
            logs: [],
            paymentRecords: []
        });
      }
      setLoading(false);
    }, 500);
  }, [id]);

  const handleApprove = () => {
    if (!detail) return;
    const newStatus = 'Approved';
    const newLog = { 
      time: new Date().toLocaleString(), 
      user: '当前用户', 
      action: '财务确认', 
      comment: '同意' 
    };
    setDetail({
      ...detail,
      status: newStatus,
      logs: [...detail.logs, newLog]
    });
    message.success('审批通过，进入待付款状态');
  };

  const handleReject = () => {
    if (!detail) return;
    const newStatus = 'Rejected';
    const newLog = { 
      time: new Date().toLocaleString(), 
      user: '当前用户', 
      action: '驳回', 
      comment: rejectReason 
    };
    setDetail({
        ...detail,
        status: newStatus,
        logs: [...detail.logs, newLog]
    });
    setIsRejectModalOpen(false);
    message.error('审批已驳回');
  };

  const handlePay = () => {
    if (!detail) return;
    const newStatus = 'Paid';
    const newLog = { 
      time: new Date().toLocaleString(), 
      user: '当前用户', 
      action: '出纳付款', 
      comment: '已完成支付' 
    };
    // Simulate creating a payment record
    const newRecord: PaymentRecord = {
        slipNo: `SLIP${new Date().toISOString().slice(0,10).replace(/-/g,'')}${Math.floor(Math.random()*1000)}`,
        amount: detail.amount.applied,
        paymentTime: new Date().toLocaleString(),
        vouchers: [{ name: '模拟回单.jpg', url: 'https://via.placeholder.com/300?text=NewVoucher' }]
    };

    setDetail({
        ...detail,
        status: newStatus,
        amount: { ...detail.amount, actual: detail.amount.applied, unpaid: 0 },
        logs: [...detail.logs, newLog],
        paymentRecords: [...detail.paymentRecords, newRecord]
    });
    message.success('付款完成');
  };

  const getStepCurrent = () => {
    if (!detail) return 0;
    if (detail.status === 'Pending') return 1;
    if (detail.status === 'Approved') return 2;
    if (detail.status === 'Paid') return 3;
    if (detail.status === 'Rejected') return 1; 
    return 0;
  };

  if (loading) {
      return <div style={{ padding: 50, textAlign: 'center' }}><Spin size="large" /></div>;
  }

  if (!detail) {
      return <div>数据加载失败</div>;
  }

  return (
    <div style={{ padding: 24, background: '#f0f2f5' }}>
      <PageDoc 
        pageTitle="供应链管理 > 供应商管理 > 预付款详情"
        description="查看预付款申请的完整详情及审批记录。系统实现了付款凭证与水单号的严格绑定，当状态为'已付款'或'部分付款'时，可查看每一笔水单对应的具体凭证（支持多张），确保财务数据的可追溯性。"
        fields={[]}
      />
      <Breadcrumb style={{ marginBottom: 16 }} items={[
         { title: '供应链管理' },
         { title: <a onClick={() => navigate('/supply-chain/supplier')}>供应商管理</a> },
         { title: <a onClick={() => navigate(-1)}>预付款审批列表</a> },
         { title: '详情' }
      ]} />

      <Space direction="vertical" size="large" style={{ width: '100%' }}>
        <Card title="基础信息" variant="borderless">
          <Descriptions column={{ xxl: 3, xl: 3, lg: 3, md: 3, sm: 2, xs: 1 }}>
            <Descriptions.Item label="预付款单号">{detail.id}</Descriptions.Item>
            <Descriptions.Item label="审批状态">
               <Tag color={detail.status === 'Pending' ? 'orange' : detail.status === 'Paid' ? 'green' : detail.status === 'Approved' ? 'blue' : detail.status === 'PartiallyPaid' ? 'cyan' : 'red'}>
                 {detail.status === 'Pending' ? '待审批' : detail.status === 'Approved' ? '待付款' : detail.status === 'Paid' ? '已付款' : detail.status === 'PartiallyPaid' ? '部分付款' : '已驳回'}
               </Tag>
            </Descriptions.Item>
            {(detail.status === 'Paid' || detail.status === 'PartiallyPaid') && (
              <Descriptions.Item label="付款水单号">
                {detail.paymentRecords && detail.paymentRecords.length > 0 ? (
                   <Space direction="vertical" size={0}>
                      {detail.paymentRecords.map((record, idx) => <span key={idx}>{record.slipNo}</span>)}
                   </Space>
                ) : '-'}
              </Descriptions.Item>
            )}
            <Descriptions.Item label="业务类型">{detail.businessType}</Descriptions.Item>
          </Descriptions>
        </Card>

        <Card title="收付款信息" variant="borderless">
          <Descriptions title="付款方信息" column={{ xxl: 3, xl: 3, lg: 3, md: 3, sm: 2, xs: 1 }} style={{ marginBottom: 16 }}>
            <Descriptions.Item label="名称">{detail.payer.name}</Descriptions.Item>
            <Descriptions.Item label="开户行">{detail.payer.bank}</Descriptions.Item>
            <Descriptions.Item label="银行账号">{detail.payer.account}</Descriptions.Item>
          </Descriptions>
          <Divider />
          <Descriptions title="收款方信息" column={3}>
            <Descriptions.Item label="名称">{detail.payee.name}</Descriptions.Item>
            <Descriptions.Item label="开户行">{detail.payee.bank}</Descriptions.Item>
            <Descriptions.Item label="银行账号">{detail.payee.account}</Descriptions.Item>
          </Descriptions>
        </Card>

        <Card title="联系与金额" variant="borderless">
           <Descriptions column={{ xxl: 3, xl: 3, lg: 3, md: 3, sm: 2, xs: 1 }}>
             <Descriptions.Item label="供应商联系人">{detail.contact.name}</Descriptions.Item>
             <Descriptions.Item label="联系电话">{detail.contact.phone}</Descriptions.Item>
             <Descriptions.Item label="申请预付金额">¥{detail.amount.applied.toLocaleString()}</Descriptions.Item>
             <Descriptions.Item label="实际预付金额">¥{detail.amount.actual.toLocaleString()}</Descriptions.Item>
             <Descriptions.Item label="未付金额">¥{detail.amount.unpaid.toLocaleString()}</Descriptions.Item>
           </Descriptions>
        </Card>

        <Card title="附件信息" variant="borderless">
           <Space>
             {detail.attachments.map((file, index) => (
                <div key={index} style={{ border: '1px solid #d9d9d9', padding: 8, borderRadius: 4 }}>
                   <Image width={100} src={file.url} alt={file.name} fallback="https://via.placeholder.com/150?text=File" />
                   <div style={{ textAlign: 'center', marginTop: 4 }}>{file.name}</div>
                </div>
             ))}
           </Space>
        </Card>

        {detail.paymentRecords && detail.paymentRecords.length > 0 && (
           <Card title="付款凭证" variant="borderless">
              <Timeline>
                {detail.paymentRecords.map((record, index) => (
                  <Timeline.Item key={index} color="green">
                    <Space direction="vertical" style={{ width: '100%' }}>
                      <div style={{ fontWeight: 'bold', marginBottom: 8 }}>
                        <span>水单号：{record.slipNo}</span>
                        <Divider type="vertical" />
                        <span>金额：¥{record.amount.toLocaleString()}</span>
                        <Divider type="vertical" />
                        <span style={{ color: '#999', fontWeight: 'normal' }}>{record.paymentTime}</span>
                      </div>
                      <Space size="large" wrap>
                        {record.vouchers.map((v, i) => (
                            <div key={i} style={{ textAlign: 'center' }}>
                              <Image width={200} src={v.url} alt={v.name} />
                              <div style={{ marginTop: 8, color: '#666' }}>{v.name}</div>
                            </div>
                        ))}
                      </Space>
                    </Space>
                  </Timeline.Item>
                ))}
              </Timeline>
           </Card>
        )}

        <Card variant="borderless">
          <Steps 
            direction="vertical" 
            current={getStepCurrent()} 
            status={detail.status === 'Rejected' ? 'error' : 'process'}
            items={[
                { title: "提交申请", description: detail.logs[0]?.time || '' },
                { title: "财务审核", description: detail.status !== 'Pending' ? '已完成' : '进行中' },
                { title: "出纳付款", description: detail.status === 'Paid' ? '已完成' : '待处理' },
                { title: "完成" }
            ]}
          />
        </Card>

        <Card title="操作记录" variant="borderless">
           <Table
              dataSource={[...detail.logs].reverse()}
              pagination={{ pageSize: 10 }}
              rowKey="time"
              columns={[
                  { title: '操作时间', dataIndex: 'time', key: 'time' },
                  { title: '操作人', key: 'user', render: (_, record) => (
                      <Space>
                        <Avatar icon={<UserOutlined />} size="small" />
                        <span>{record.user}</span>
                      </Space>
                  )},
                  { title: '操作类型', key: 'action', render: (_, record) => (
                      <Tag color="blue">{record.action}</Tag>
                  )},
                  { title: '备注', dataIndex: 'comment', key: 'comment' },
              ]}
           />
        </Card>
      </Space>

      <div style={{ position: 'fixed', bottom: 0, right: 0, width: '100%', background: '#fff', padding: '16px 24px', borderTop: '1px solid #e8e8e8', textAlign: 'right', zIndex: 999 }}>
         <Space>
            <Button onClick={() => navigate(-1)}>返回</Button>
            {detail.status === 'Pending' && (
               <>
                 <Button danger onClick={() => setIsRejectModalOpen(true)}>驳回</Button>
                 <Button type="primary" onClick={handleApprove}>财务确认</Button>
               </>
            )}
            {detail.status === 'Approved' && (
               <Button type="primary" icon={<PayCircleOutlined />} onClick={handlePay}>出纳付款</Button>
            )}
         </Space>
      </div>

      <Modal title="驳回原因" open={isRejectModalOpen} onOk={handleReject} onCancel={() => setIsRejectModalOpen(false)}>
         <Input.TextArea rows={4} value={rejectReason} onChange={e => setRejectReason(e.target.value)} placeholder="请输入驳回原因" />
      </Modal>
      <div style={{ height: 60 }} /> {/* Spacer for fixed footer */}
    </div>
  );
};

export default SupplierPrepaymentDetail;

import React, { useState } from 'react';
import { Table, Button, Input, Space, Tag, message, Breadcrumb, DatePicker, Select, Modal, Form, Upload, Row, Col } from 'antd';
import type { ColumnsType } from 'antd/es/table';
import { PlusOutlined, SearchOutlined, FileTextOutlined, UploadOutlined, UndoOutlined } from '@ant-design/icons';
import { useNavigate, useParams } from 'react-router-dom';
import PageDoc from '../../components/PageDoc';

interface PrepaymentApplyItem {
  key: string;
  id: string; // YF+...
  appliedAmount: number;
  paidAmount: number;
  lastPaymentTime: string;
  applyTime: string;
  applicant: string;
  status: 'Pending' | 'Approved' | 'Rejected' | 'Paid';
}

const mockData: PrepaymentApplyItem[] = [
  {
    key: '1',
    id: 'YF20231001103001',
    appliedAmount: 50000.00,
    paidAmount: 50000.00,
    lastPaymentTime: '2023-10-01 10:00:00',
    applyTime: '2023-09-30 14:20:00',
    applicant: '张三',
    status: 'Paid',
  },
  {
    key: '2',
    id: 'YF20231005142002',
    appliedAmount: 20000.00,
    paidAmount: 0.00,
    lastPaymentTime: '-',
    applyTime: '2023-10-05 09:15:30',
    applicant: '李四',
    status: 'Pending',
  }
];

const SupplierPrepaymentList: React.FC = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const [data, setData] = useState<PrepaymentApplyItem[]>(mockData);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [form] = Form.useForm();

  // Mock supplier info (In real app, fetch by id)
  const supplierInfo = {
    name: '上海晨光文具销售有限公司',
    account: '622202...',
    bank: '中国工商银行',
    payerName: '我的企业',
    payerAccount: '1234567890',
    payerBank: '招商银行'
  };

  const handleAdd = () => {
    setIsModalOpen(true);
    form.setFieldsValue({
      payerName: supplierInfo.payerName,
      payerAccount: supplierInfo.payerAccount,
      payerBank: supplierInfo.payerBank,
      payee: supplierInfo.name,
      account: supplierInfo.account,
      payeeBank: supplierInfo.bank,
    });
  };

  const handleOk = () => {
    form.validateFields().then(values => {
      const newId = `YF${new Date().toISOString().slice(0,10).replace(/-/g,'')}${new Date().getHours()}${new Date().getMinutes()}0${data.length + 1}`;
      const newItem: PrepaymentApplyItem = {
        key: Date.now().toString(),
        id: newId,
        appliedAmount: values.amount,
        paidAmount: 0,
        lastPaymentTime: '-',
        applyTime: new Date().toLocaleString('zh-CN', { hour12: false }).replace(/\//g, '-'),
        applicant: '当前用户',
        status: 'Pending',
      };
      setData([newItem, ...data]);
      setIsModalOpen(false);
      form.resetFields();
      message.success('预付款申请已提交');
    });
  };

  const columns: ColumnsType<PrepaymentApplyItem> = [
    { title: '预付款单号', dataIndex: 'id', key: 'id' },
    { 
      title: '申请金额', 
      dataIndex: 'appliedAmount', 
      key: 'appliedAmount',
      render: (val) => `¥${val.toLocaleString(undefined, { minimumFractionDigits: 2 })}`
    },
    { 
      title: '实付金额', 
      dataIndex: 'paidAmount', 
      key: 'paidAmount',
      render: (val) => `¥${val.toLocaleString(undefined, { minimumFractionDigits: 2 })}`
    },
    { title: '申请日期', dataIndex: 'applyTime', key: 'applyTime' },
    { title: '最后付款时间', dataIndex: 'lastPaymentTime', key: 'lastPaymentTime' },
    { title: '申请人', dataIndex: 'applicant', key: 'applicant' },
    { 
      title: '审批状态', 
      dataIndex: 'status', 
      key: 'status',
      render: (status) => {
        const colorMap: Record<string, string> = {
          Pending: 'orange',
          Approved: 'blue',
          Rejected: 'red',
          Paid: 'green'
        };
        const textMap: Record<string, string> = {
          Pending: '待审批',
          Approved: '待付款',
          Rejected: '已驳回',
          Paid: '已付款'
        };
        return <Tag color={colorMap[status]}>{textMap[status]}</Tag>;
      }
    },
    {
      title: '操作',
      key: 'action',
      render: (_, record) => (
        <Button type="link" size="small" icon={<FileTextOutlined />} onClick={() => navigate(`/supply-chain/supplier/prepayment-detail/${record.id}`)}>
          查看详情
        </Button>
      )
    }
  ];

  return (
    <div style={{ background: '#fff', padding: 24, minHeight: 360 }}>
      <PageDoc 
        pageTitle="供应链管理 > 供应商管理 > 预付款审批列表"
        description="管理供应商的预付款申请及审批流程。支持按单号、付款日期、申请人及审批状态进行组合搜索。"
        fields={[
           { name: 'id', type: 'String', desc: '预付款单号 (YF+年月日时分+两位顺序号)', required: false },
           { name: 'appliedAmount', type: 'Decimal', desc: '申请金额' },
           { name: 'lastPaymentTime', type: 'DateTime', desc: '最后付款时间：自动获取该单据关联的最近一次付款时间' },
           { name: 'status', type: 'Enum', desc: '状态：待审批、待付款、已付款、已驳回' }
        ]}
      />

      <Breadcrumb style={{ marginBottom: 16 }} items={[
         { title: '供应链管理' },
         { title: <a onClick={() => navigate('/supply-chain/supplier')}>供应商管理</a> },
         { title: '预付款审批列表' }
      ]} />

      <div style={{ marginBottom: 16, display: 'flex', justifyContent: 'space-between' }}>
        <Space>
          <Button type="primary" icon={<PlusOutlined />} onClick={handleAdd}>新增预付款</Button>
          <Button icon={<FileTextOutlined />} onClick={() => navigate(`/supply-chain/supplier/prepayment-log/${id}`)}>查看资金流水</Button>
        </Space>
      </div>

      <Table 
        columns={columns} 
        dataSource={data} 
        onRow={(record) => {
          return {
            onClick: () => {
              navigate(`/supply-chain/supplier/prepayment-detail/${record.id}`);
            },
            style: { cursor: 'pointer' }
          };
        }}
      />

      <Modal
        title="新增预付款申请"
        open={isModalOpen}
        onOk={handleOk}
        onCancel={() => setIsModalOpen(false)}
        width={800}
      >
        <Form form={form} layout="vertical">
          <Row gutter={16}>
             <Col span={8}>
                <Form.Item name="payerName" label="付款方名称" rules={[{ required: true }]}>
                  <Input />
                </Form.Item>
             </Col>
             <Col span={8}>
                <Form.Item name="payerAccount" label="付款账号" rules={[{ required: true }]}>
                  <Input />
                </Form.Item>
             </Col>
             <Col span={8}>
                <Form.Item name="payerBank" label="开户行" rules={[{ required: true }]}>
                  <Input />
                </Form.Item>
             </Col>
          </Row>

          <Row gutter={16}>
             <Col span={8}>
                <Form.Item name="payee" label="收款方名称" rules={[{ required: true }]}>
                  <Input />
                </Form.Item>
             </Col>
             <Col span={8}>
                <Form.Item name="account" label="收款账号" rules={[{ required: true }]}>
                  <Input />
                </Form.Item>
             </Col>
             <Col span={8}>
                <Form.Item name="payeeBank" label="开户行" rules={[{ required: true }]}>
                  <Input />
                </Form.Item>
             </Col>
          </Row>

          <Form.Item name="amount" label="申请金额" rules={[{ required: true }]}>
             <Input 
                prefix="¥" 
                type="number"
                placeholder="请输入申请金额" 
             />
          </Form.Item>

          <Form.Item 
            name="invoice" 
            label="成本票/附件" 
            valuePropName="fileList"
            getValueFromEvent={(e) => {
                if (Array.isArray(e)) return e;
                return e?.fileList;
            }}
          >
            <Upload action="/upload.do" listType="picture" maxCount={5}>
              <Button icon={<UploadOutlined />}>上传附件</Button>
            </Upload>
          </Form.Item>

          <Form.Item name="note" label="申请备注">
            <Input.TextArea rows={3} />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
};

export default SupplierPrepaymentList;

import React, { useState } from 'react';
